import{n as e}from"./PlaceholderImage-BuF9HK_j.js";var t=[{id:`rec-1`,name:`土豆烧牛肉`,difficulty:`medium`,duration:`45分钟`,cuisine:`家常`,ingredients:[{name:`牛肉`,amount:`300g`},{name:`土豆`,amount:`2个`},{name:`胡萝卜`,amount:`1根`},{name:`洋葱`,amount:`半个`},{name:`生抽`,amount:`2勺`},{name:`老抽`,amount:`1勺`},{name:`生姜`,amount:`3片`},{name:`八角`,amount:`2个`}],steps:[{order:1,text:`牛肉切块，冷水下锅焯水，水沸后捞出洗净浮沫。`,image:e},{order:2,text:`土豆、胡萝卜去皮切滚刀块，洋葱切片，姜切片备用。`,image:e},{order:3,text:`锅中倒油，放入姜片、八角爆香，加入牛肉翻炒至表面微黄。`,image:e},{order:4,text:`加入生抽、老抽翻炒上色，倒入没过牛肉的热水，大火烧开后转小火炖30分钟。`,image:e},{order:5,text:`加入土豆、胡萝卜和洋葱，继续炖15分钟至土豆软烂，收汁即可。`,image:e}],tips:`牛肉先焯水可以去除血水和腥味；炖牛肉时加热水，冷水会让肉质紧缩变柴。`,coverImage:`/images/recipes/土豆烧牛肉.png`},{id:`rec-2`,name:`番茄炒蛋`,difficulty:`easy`,duration:`10分钟`,cuisine:`家常`,ingredients:[{name:`番茄`,amount:`2个`},{name:`鸡蛋`,amount:`3个`},{name:`大葱`,amount:`1根`},{name:`盐`,amount:`适量`},{name:`糖`,amount:`半勺`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`番茄洗净切小块，鸡蛋打散加少许盐搅匀，葱切葱花。`,image:e},{order:2,text:`锅中倒油烧热，倒入蛋液，用筷子快速划散，凝固后盛出备用。`,image:e},{order:3,text:`锅中再倒少许油，放入番茄翻炒，加糖和少许盐，炒至番茄出汁。`,image:e},{order:4,text:`倒回炒好的鸡蛋，翻炒均匀，撒上葱花出锅。`,image:e}],tips:`番茄加少许糖可以中和酸味；鸡蛋不要炒太老，嫩滑口感最好。`,coverImage:`/images/recipes/西红柿炒鸡蛋.png`},{id:`rec-3`,name:`酸辣土豆丝`,difficulty:`easy`,duration:`15分钟`,cuisine:`川菜`,ingredients:[{name:`土豆`,amount:`2个`},{name:`干辣椒`,amount:`3个`},{name:`花椒`,amount:`10粒`},{name:`醋`,amount:`2勺`},{name:`盐`,amount:`适量`},{name:`大葱`,amount:`1根`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`土豆去皮切细丝，放入清水中浸泡去除多余淀粉，沥干备用。`,image:e},{order:2,text:`干辣椒剪段，葱切段。`,image:e},{order:3,text:`锅中倒油，放入花椒、干辣椒爆香。`,image:e},{order:4,text:`倒入土豆丝大火快炒，加盐和醋调味，翻炒均匀至土豆丝断生。`,image:e},{order:5,text:`撒上葱段翻匀出锅。土豆丝炒太久会失去脆感，全程大火快炒。`,image:e}],tips:`土豆丝切好后泡水去淀粉，炒出来才脆；全程大火快炒，不超过3分钟。`,coverImage:`/images/recipes/酸辣土豆丝.png`},{id:`rec-4`,name:`蛋炒饭`,difficulty:`easy`,duration:`10分钟`,cuisine:`家常`,ingredients:[{name:`米饭`,amount:`1碗`},{name:`鸡蛋`,amount:`2个`},{name:`大葱`,amount:`1根`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`鸡蛋打散，葱切葱花，隔夜米饭用手捏散备用。`,image:e},{order:2,text:`锅中倒油烧热，倒入蛋液快速划散，炒至凝固盛出。`,image:e},{order:3,text:`锅中加少许油，倒入米饭，用铲子压散炒热。`,image:e},{order:4,text:`倒回鸡蛋炒匀，加盐调味，撒葱花出锅。`,image:e}],tips:`隔夜米饭水分少，炒出来粒粒分明；炒饭时用大火，不停翻动防止粘锅。`,coverImage:`/images/recipes/蛋炒饭.png`},{id:`rec-5`,name:`家常豆腐`,difficulty:`easy`,duration:`20分钟`,cuisine:`家常`,ingredients:[{name:`豆腐`,amount:`1块`},{name:`猪肉`,amount:`100g`},{name:`豆瓣酱`,amount:`1勺`},{name:`生抽`,amount:`1勺`},{name:`大葱`,amount:`1根`},{name:`生姜`,amount:`2片`},{name:`大蒜`,amount:`2瓣`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`豆腐切成2cm方块，放入加盐的热水中焯2分钟，沥干备用。`,image:e},{order:2,text:`姜蒜切末，葱切段。`,image:e},{order:3,text:`锅中倒油，放入肉末煸炒至变色，加入姜蒜末、豆瓣酱炒出红油。`,image:e},{order:4,text:`加少许水，放入豆腐轻轻推匀，加生抽调味，小火煮5分钟入味。`,image:e},{order:5,text:`大火收汁，撒上葱段出锅。`,image:e}],tips:`豆腐焯水可以去除豆腥味并使其更紧实不易碎；煮豆腐时轻轻翻动，保持完整。`,coverImage:e},{id:`rec-6`,name:`清炒青菜`,difficulty:`easy`,duration:`5分钟`,cuisine:`家常`,ingredients:[{name:`青菜`,amount:`300g`},{name:`大蒜`,amount:`3瓣`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`青菜洗净切段，蒜拍碎切末。`,image:e},{order:2,text:`锅中倒油烧热，放入蒜末爆香。`,image:e},{order:3,text:`倒入青菜大火快炒，加盐调味，炒至叶片变软即可出锅。`,image:e}],tips:`炒青菜全程大火，时间不超过3分钟，保持脆嫩口感和翠绿色泽。`,coverImage:e},{id:`rec-7`,name:`麻婆豆腐`,difficulty:`easy`,duration:`15分钟`,cuisine:`川菜`,ingredients:[{name:`豆腐`,amount:`1块`},{name:`牛肉`,amount:`100g`},{name:`豆瓣酱`,amount:`2勺`},{name:`大蒜`,amount:`3瓣`},{name:`生姜`,amount:`2片`},{name:`大葱`,amount:`1根`},{name:`淀粉`,amount:`1勺`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`豆腐切成2cm方块，放入加盐的沸水中焯2分钟，捞出沥干备用。`,image:e},{order:2,text:`姜蒜切末，葱切葱花。锅中倒油烧热，放入姜末、蒜末、豆瓣酱，小火煸炒出红油。`,image:e},{order:3,text:`加入牛肉末，中火翻炒至肉末变色散开，炒出香味。`,image:e},{order:4,text:`加入半碗清水，放入焯好的豆腐块，轻轻推匀，小火煮3分钟入味。`,image:e},{order:5,text:`淋入水淀粉勾薄芡，轻轻翻匀，撒上葱花出锅。`,image:e}],tips:`豆腐焯水后更紧实不易碎；翻炒时用推的方式而不是翻，保持豆腐完整。`,coverImage:e},{id:`rec-8`,name:`回锅肉`,difficulty:`medium`,duration:`20分钟`,cuisine:`川菜`,ingredients:[{name:`猪肉`,amount:`300g`},{name:`青蒜`,amount:`3根`},{name:`豆瓣酱`,amount:`2勺`},{name:`甜面酱`,amount:`1勺`},{name:`生姜`,amount:`3片`},{name:`大蒜`,amount:`3瓣`},{name:`食用油`,amount:`1勺`}],steps:[{order:1,text:`五花肉整块冷水下锅，加姜片煮至筷子能戳透（约15分钟），捞出晾凉切薄片。`,image:e},{order:2,text:`青蒜苗斜切成段，蒜拍碎。煮肉的汤留用。`,image:e},{order:3,text:`锅中倒少许油，放入五花肉片，中火煸炒至肉片卷曲呈灯盏窝状，肥肉部分透明出油。`,image:e},{order:4,text:`将肉推至一边，放入豆瓣酱、蒜末炒出红油，再与肉片翻炒均匀。`,image:e},{order:5,text:`加入甜面酱翻炒上色，放入青蒜苗大火快炒至断生，即可出锅。`,image:e}],tips:`五花肉煮到八分熟即可，太熟切片易碎；煸炒时把油逼出来，肉片才香而不腻。`,coverImage:e},{id:`rec-9`,name:`鱼香肉丝`,difficulty:`medium`,duration:`20分钟`,cuisine:`川菜`,ingredients:[{name:`猪肉`,amount:`250g`},{name:`木耳`,amount:`50g`},{name:`胡萝卜`,amount:`1根`},{name:`泡椒`,amount:`3个`},{name:`生姜`,amount:`2片`},{name:`大蒜`,amount:`3瓣`},{name:`大葱`,amount:`1根`},{name:`生抽`,amount:`1勺`},{name:`醋`,amount:`1勺`},{name:`糖`,amount:`1勺`},{name:`淀粉`,amount:`1勺`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`猪里脊切细丝，加少许盐、淀粉和油抓匀腌制10分钟。木耳泡发切丝，胡萝卜去皮切丝。`,image:e},{order:2,text:`调鱼香汁：碗中混合生抽、醋、糖、淀粉和2勺清水，搅匀备用。`,image:e},{order:3,text:`泡椒剁碎，姜蒜切末，葱切葱花。锅中倒油烧热，下肉丝滑炒至变色盛出。`,image:e},{order:4,text:`锅中留底油，放入泡椒末、姜蒜末爆香，加入木耳丝和胡萝卜丝翻炒至断生。`,image:e},{order:5,text:`倒回肉丝翻炒均匀，淋入鱼香汁，大火快速翻炒至汁浓，撒葱花出锅。`,image:e}],tips:`鱼香汁的糖醋比例约为1:1，可根据口味微调；肉丝滑炒时油温不要太热，变色即可盛出。`,coverImage:e},{id:`rec-10`,name:`宫保鸡丁`,difficulty:`easy`,duration:`18分钟`,cuisine:`川菜`,ingredients:[{name:`鸡肉`,amount:`250g`},{name:`花生`,amount:`50g`},{name:`干辣椒`,amount:`6个`},{name:`花椒`,amount:`1小勺`},{name:`生姜`,amount:`2片`},{name:`大蒜`,amount:`3瓣`},{name:`大葱`,amount:`1根`},{name:`生抽`,amount:`1勺`},{name:`醋`,amount:`1勺`},{name:`糖`,amount:`1勺`},{name:`淀粉`,amount:`1勺`},{name:`食用油`,amount:`3勺`}],steps:[{order:1,text:`鸡胸肉切1.5cm小丁，加少许盐、淀粉、料酒抓匀腌制15分钟。`,image:e},{order:2,text:`干辣椒剪段去籽，姜蒜切片，葱切小段。调碗汁：生抽、醋、糖、淀粉加2勺水混合。`,image:e},{order:3,text:`冷锅冷油放入花生米，小火慢炸至金黄酥脆，捞出沥油备用。`,image:e},{order:4,text:`锅中油烧至六成热，下鸡丁滑炒至变白断生，盛出。`,image:e},{order:5,text:`锅中留底油，放花椒、干辣椒小火煸出香味，加入姜蒜葱炒香，倒入鸡丁翻炒。`,image:e},{order:6,text:`淋入碗汁，大火快速翻炒收汁，最后加入花生米翻匀出锅。`,image:e}],tips:`花生米要冷油下锅小火慢炸，听到噼啪声即可捞出，余温会继续加热避免炸焦。`,coverImage:e},{id:`rec-11`,name:`水煮鱼`,difficulty:`medium`,duration:`30分钟`,cuisine:`川菜`,ingredients:[{name:`草鱼`,amount:`1条（约750g）`},{name:`豆芽`,amount:`200g`},{name:`干辣椒`,amount:`10个`},{name:`花椒`,amount:`2小勺`},{name:`生姜`,amount:`5片`},{name:`大蒜`,amount:`5瓣`},{name:`豆瓣酱`,amount:`2勺`},{name:`淀粉`,amount:`2勺`},{name:`蛋清`,amount:`1个`},{name:`食用油`,amount:`4勺`}],steps:[{order:1,text:`草鱼去骨，鱼肉片成薄片，加盐、料酒、蛋清、淀粉抓匀腌制15分钟。鱼骨斩段备用。`,image:e},{order:2,text:`豆芽焯水至断生，铺在大碗底部。干辣椒剪段，姜蒜切片。`,image:e},{order:3,text:`锅中倒油，放入姜蒜、豆瓣酱炒出红油，加入鱼骨翻炒，倒入足量清水烧开。`,image:e},{order:4,text:`水沸后将腌制好的鱼片逐片滑入锅中，用筷子轻轻拨散，煮约1分钟至鱼片变白断生。`,image:e},{order:5,text:`将鱼片和汤一起倒入铺好豆芽的碗中，撒上干辣椒段和花椒。另起锅烧热油，淋在辣椒花椒上激香。`,image:e}],tips:`鱼片不要煮太久，变白即可，否则口感会老；最后淋热油是关键步骤，油温要够高才能激出香味。`,coverImage:e},{id:`rec-12`,name:`辣子鸡`,difficulty:`medium`,duration:`25分钟`,cuisine:`川菜`,ingredients:[{name:`鸡肉`,amount:`2个`},{name:`干辣椒`,amount:`15个`},{name:`花椒`,amount:`2小勺`},{name:`生姜`,amount:`3片`},{name:`大蒜`,amount:`4瓣`},{name:`料酒`,amount:`1勺`},{name:`生抽`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`白芝麻`,amount:`1勺`},{name:`食用油`,amount:`适量（炸用）`}],steps:[{order:1,text:`鸡腿斩成小块，加料酒、生抽、盐腌制20分钟。干辣椒剪段，姜蒜切片。`,image:e},{order:2,text:`锅中倒足量油烧至七成热（插入筷子冒密集气泡），放入鸡块中火炸至表面金黄酥脆，捞出沥油。`,image:e},{order:3,text:`锅中留底油，小火放入花椒、干辣椒段慢慢煸炒，炒至辣椒颜色变深、香味飘出。`,image:e},{order:4,text:`转大火，加入姜蒜片爆香，倒入炸好的鸡块快速翻炒均匀。`,image:e},{order:5,text:`撒入盐和少许糖调味，翻炒均匀后撒上白芝麻，出锅装盘。`,image:e}],tips:`鸡块炸两次更酥脆（第一次炸熟，复炸30秒上色）；干辣椒用热水泡5分钟再炒不易焦苦。`,coverImage:e},{id:`rec-13`,name:`干煸豆角`,difficulty:`easy`,duration:`15分钟`,cuisine:`川菜`,ingredients:[{name:`豆角`,amount:`300g`},{name:`猪肉`,amount:`80g`},{name:`干辣椒`,amount:`5个`},{name:`花椒`,amount:`1小勺`},{name:`大蒜`,amount:`3瓣`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`3勺`}],steps:[{order:1,text:`豆角洗净去筋，掰成5cm的段，沥干水分（一定要沥干，防止下锅溅油）。`,image:e},{order:2,text:`干辣椒剪段，蒜切末。锅中多倒些油烧至六成热，放入豆角炸至表皮起皱、颜色变深，捞出控油。`,image:e},{order:3,text:`锅中留底油，放入花椒、干辣椒小火煸香，加入蒜末炒出香味。`,image:e},{order:4,text:`放入肉末，中火翻炒至变色散开，炒出油脂。`,image:e},{order:5,text:`倒入炸好的豆角，加盐调味，翻炒均匀即可出锅。`,image:e}],tips:`豆角表皮一定要炸皱才有干煸的风味；生豆角含有毒素，务必炸熟炸透。`,coverImage:e},{id:`rec-14`,name:`水煮肉片`,difficulty:`medium`,duration:`25分钟`,cuisine:`川菜`,ingredients:[{name:`猪肉`,amount:`300g`},{name:`生菜`,amount:`1棵`},{name:`豆芽`,amount:`150g`},{name:`干辣椒`,amount:`10个`},{name:`花椒`,amount:`2小勺`},{name:`生姜`,amount:`3片`},{name:`大蒜`,amount:`4瓣`},{name:`豆瓣酱`,amount:`2勺`},{name:`淀粉`,amount:`2勺`},{name:`蛋清`,amount:`1个`},{name:`食用油`,amount:`4勺`}],steps:[{order:1,text:`猪里脊切薄片，加盐、料酒、蛋清、淀粉抓匀，腌制15分钟至肉片上浆。`,image:e},{order:2,text:`生菜洗净撕大块，豆芽洗净。锅中烧水，分别将豆芽和生菜焯至断生，铺在大碗底部。`,image:e},{order:3,text:`姜蒜切末。锅中倒油，放入姜蒜末、豆瓣酱，小火炒出红油，加入适量清水烧开。`,image:e},{order:4,text:`水沸后将肉片逐片下入锅中，用筷子轻轻拨散，煮至肉片变白（约30秒）立即关火。`,image:e},{order:5,text:`将肉片和汤汁倒入铺好蔬菜的碗中，撒上干辣椒段和花椒，另起锅烧热油淋在上面激香。`,image:e}],tips:`肉片切得越薄越嫩；下锅后不要过度搅拌，煮到变色立刻出锅，余温会继续加热。`,coverImage:e},{id:`rec-15`,name:`夫妻肺片`,difficulty:`medium`,duration:`25分钟`,cuisine:`川菜`,ingredients:[{name:`牛腱`,amount:`200g`},{name:`牛肉`,amount:`150g`},{name:`牛肉`,amount:`150g`},{name:`辣椒油`,amount:`3勺`},{name:`花椒`,amount:`1小勺`},{name:`花生`,amount:`2勺`},{name:`大蒜`,amount:`3瓣`},{name:`生抽`,amount:`2勺`},{name:`醋`,amount:`1勺`},{name:`糖`,amount:`半勺`},{name:`香菜`,amount:`适量`}],steps:[{order:1,text:`牛腱、牛舌、牛肚冷水下锅，加姜片、料酒焯水去腥，捞出洗净。`,image:e},{order:2,text:`另起锅，将牛腱、牛舌、牛肚放入，加足量水、姜片、八角，大火烧开转小火煮1小时至熟透。`,image:e},{order:3,text:`捞出晾凉，分别切成薄片，牛肚切条，整齐码放在盘中。`,image:e},{order:4,text:`调麻辣料汁：碗中混合辣椒油、花椒粉、蒜末、生抽、醋、糖和少许煮肉的汤，搅匀。`,image:e},{order:5,text:`将料汁均匀淋在肉片上，撒上花生碎和香菜，拌匀后冷藏30分钟入味更佳。`,image:e}],tips:`肉类冷藏后切片更薄更整齐；料汁可以提前调好放半小时让味道融合，冷藏后风味更佳。`,coverImage:e},{id:`rec-16`,name:`毛血旺`,difficulty:`medium`,duration:`30分钟`,cuisine:`川菜`,ingredients:[{name:`鸭肉`,amount:`200g`},{name:`毛肚`,amount:`150g`},{name:`黄喉`,amount:`100g`},{name:`猪肉`,amount:`半罐`},{name:`豆芽`,amount:`150g`},{name:`干辣椒`,amount:`10个`},{name:`花椒`,amount:`2小勺`},{name:`豆瓣酱`,amount:`2勺`},{name:`生姜`,amount:`3片`},{name:`大蒜`,amount:`5瓣`},{name:`食用油`,amount:`4勺`},{name:`香菜`,amount:`适量`}],steps:[{order:1,text:`鸭血切厚片，毛肚切条，黄喉切段，午餐肉切片。分别放入沸水中焯水30秒，捞出备用。`,image:e},{order:2,text:`豆芽焯水铺在大碗底。干辣椒剪段，姜蒜切片。`,image:e},{order:3,text:`锅中倒油，放入姜蒜片、豆瓣酱小火炒出红油，加入约500ml清水或高汤，大火烧开。`,image:e},{order:4,text:`放入鸭血、毛肚、黄喉、午餐肉，煮约2分钟至食材充分入味。`,image:e},{order:5,text:`将煮好的食材连汤倒入铺好豆芽的碗中，撒上干辣椒段和花椒。另起锅烧热油，淋在上面激香，撒香菜即可。`,image:e}],tips:`毛肚和黄喉不宜久煮，焯水后最后下锅煮1分钟即可，煮久了会变老咬不动。`,coverImage:e},{id:`rec-17`,name:`炝炒莲白`,difficulty:`easy`,duration:`8分钟`,cuisine:`川菜`,ingredients:[{name:`包菜`,amount:`半个`},{name:`干辣椒`,amount:`5个`},{name:`花椒`,amount:`1小勺`},{name:`大蒜`,amount:`3瓣`},{name:`盐`,amount:`适量`},{name:`糖`,amount:`少许`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`包菜手撕成大块（不用刀切，手撕更入味），洗净沥干水分。干辣椒剪段，蒜切片。`,image:e},{order:2,text:`锅中倒油烧热，放入花椒、干辣椒段小火煸出香味，注意不要炒焦。`,image:e},{order:3,text:`放入蒜片爆香，转大火，倒入包菜快速翻炒，让每片都裹上油。`,image:e},{order:4,text:`包菜变软后加盐和少许糖调味，翻炒均匀即可出锅。全程不超过3分钟，保持脆嫩口感。`,image:e}],tips:`包菜一定要手撕，刀切会破坏纤维口感差；炝炒类菜品全程大火，出锅要快。`,coverImage:e},{id:`rec-18`,name:`蒜苔肉丝`,difficulty:`easy`,duration:`15分钟`,cuisine:`川菜`,ingredients:[{name:`蒜苔`,amount:`250g`},{name:`猪肉`,amount:`200g`},{name:`生姜`,amount:`2片`},{name:`大蒜`,amount:`2瓣`},{name:`生抽`,amount:`1勺`},{name:`淀粉`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`猪里脊切细丝，加少许盐、淀粉、生抽抓匀腌制10分钟。`,image:e},{order:2,text:`蒜苔洗净切4cm长的段，姜切丝，蒜切片。`,image:e},{order:3,text:`锅中倒油烧至五成热，放入肉丝滑炒至变色，盛出备用。`,image:e},{order:4,text:`锅中留底油，放入姜丝蒜片爆香，倒入蒜苔大火翻炒至颜色变深、表面起皱。`,image:e},{order:5,text:`倒回肉丝翻炒均匀，加盐调味，翻炒几下即可出锅。`,image:e}],tips:`蒜苔不要焯水直接生炒，大火快炒才能保持脆甜口感；肉丝先滑炒盛出可以避免炒老。`,coverImage:e},{id:`rec-19`,name:`凉拌鸡丝`,difficulty:`easy`,duration:`12分钟`,cuisine:`川菜`,ingredients:[{name:`鸡肉`,amount:`1块`},{name:`黄瓜`,amount:`1根`},{name:`香菜`,amount:`2根`},{name:`辣椒油`,amount:`2勺`},{name:`生抽`,amount:`1勺`},{name:`醋`,amount:`1勺`},{name:`糖`,amount:`半勺`},{name:`大蒜`,amount:`2瓣`},{name:`盐`,amount:`适量`}],steps:[{order:1,text:`鸡胸肉冷水下锅，加姜片和料酒，水沸后煮约8分钟至熟透，捞出晾凉。`,image:e},{order:2,text:`鸡胸肉顺着纹理用手撕成细丝。黄瓜洗净切丝，香菜切段，蒜切末。`,image:e},{order:3,text:`调麻辣汁：碗中混合辣椒油、生抽、醋、糖、蒜末、盐，搅匀。`,image:e},{order:4,text:`将鸡丝、黄瓜丝、香菜放入大碗，淋入调好的麻辣汁，充分拌匀即可装盘。`,image:e}],tips:`鸡胸肉煮至刚熟即可，煮久了肉质变柴；顺着纹理撕出来的鸡丝更完整不碎。`,coverImage:e},{id:`rec-20`,name:`川味凉面`,difficulty:`easy`,duration:`10分钟`,cuisine:`川菜`,ingredients:[{name:`面条`,amount:`200g`},{name:`黄瓜`,amount:`半根`},{name:`豆芽`,amount:`100g`},{name:`辣椒油`,amount:`2勺`},{name:`醋`,amount:`1勺`},{name:`生抽`,amount:`1勺`},{name:`大蒜`,amount:`3瓣`},{name:`糖`,amount:`半勺`},{name:`芝麻酱`,amount:`1勺`}],steps:[{order:1,text:`蒜捣成蒜泥加2勺凉白开制成蒜水。黄瓜切丝，豆芽焯水过凉。`,image:e},{order:2,text:`面条入沸水煮至断生（约3分钟），捞出立即放入冰水或冷开水中过凉，沥干水分。`,image:e},{order:3,text:`面条中加少许香油拌匀防止粘连，铺在盘中。`,image:e},{order:4,text:`碗中混合辣椒油、蒜水、生抽、醋、糖、芝麻酱，搅匀成调味汁。`,image:e},{order:5,text:`在面条上码放黄瓜丝和豆芽，淋上调味汁，吃时拌匀即可。`,image:e}],tips:`面条过凉水要彻底，沥干后再拌油，这样面条不粘不坨；蒜水比生蒜更均匀入味。`,coverImage:e},{id:`rec-21`,name:`盐煎肉`,difficulty:`easy`,duration:`18分钟`,cuisine:`川菜`,ingredients:[{name:`猪肉`,amount:`300g`},{name:`青蒜`,amount:`3根`},{name:`豆瓣酱`,amount:`2勺`},{name:`生姜`,amount:`2片`},{name:`大蒜`,amount:`2瓣`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`1勺`}],steps:[{order:1,text:`五花肉切薄片（约2mm厚），不焯水。青蒜斜切成段，姜蒜切片。`,image:e},{order:2,text:`炒锅烧热，倒少许油润锅，放入五花肉片，中火慢慢煸炒。`,image:e},{order:3,text:`煸炒至肉片吐油、边缘微焦、肥肉部分透明，将肉拨至一边。`,image:e},{order:4,text:`放入豆瓣酱、姜蒜片炒出红油，与肉片翻炒均匀。`,image:e},{order:5,text:`放入青蒜段大火快炒至断生，加少许盐调味（豆瓣酱已有咸味，盐少放），翻匀出锅。`,image:e}],tips:`盐煎肉直接生炒不焯水，肉片要切薄才能炒透；煸出的油太多可以倒出一些。`,coverImage:e},{id:`rec-22`,name:`香辣鸡翅`,difficulty:`easy`,duration:`20分钟`,cuisine:`川菜`,ingredients:[{name:`鸡肉`,amount:`8个`},{name:`干辣椒`,amount:`8个`},{name:`生姜`,amount:`3片`},{name:`大蒜`,amount:`3瓣`},{name:`生抽`,amount:`2勺`},{name:`料酒`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`花椒`,amount:`1小勺`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`鸡翅洗净，每个鸡翅表面划两刀便于入味，加生抽、料酒、姜片腌制20分钟。`,image:e},{order:2,text:`干辣椒剪段，蒜切片。锅中倒油，放入鸡翅中火煎至两面金黄（每面约3分钟），盛出备用。`,image:e},{order:3,text:`锅中留底油，放入花椒、干辣椒段和蒜片小火煸出香味。`,image:e},{order:4,text:`倒回煎好的鸡翅，加少许盐，大火翻炒均匀，让辣椒的香气裹住鸡翅。`,image:e},{order:5,text:`加2勺清水焖1分钟让味道渗入，大火收干汁水，出锅装盘。`,image:e}],tips:`鸡翅表面划刀后腌制更入味；煎鸡翅时不要频繁翻动，一面煎定型再翻面，皮才完整。`,coverImage:e},{id:`rec-23`,name:`泡椒牛蛙`,difficulty:`medium`,duration:`25分钟`,cuisine:`川菜`,ingredients:[{name:`牛蛙`,amount:`2只`},{name:`泡椒`,amount:`8个`},{name:`生姜`,amount:`3片`},{name:`大蒜`,amount:`4瓣`},{name:`洋葱`,amount:`半个`},{name:`料酒`,amount:`1勺`},{name:`生抽`,amount:`1勺`},{name:`淀粉`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`3勺`}],steps:[{order:1,text:`牛蛙宰杀洗净斩块，加料酒、盐、淀粉抓匀腌制15分钟。泡椒切段，姜蒜切片，洋葱切块。`,image:e},{order:2,text:`锅中倒油烧至六成热，放入牛蛙块滑炒至表面变白定型，盛出备用。`,image:e},{order:3,text:`锅中留底油，放入姜蒜片、泡椒段、洋葱块爆香，炒出泡椒的酸辣味。`,image:e},{order:4,text:`倒入牛蛙块翻炒均匀，加入生抽和半碗清水，盖上锅盖中小火焖8分钟。`,image:e},{order:5,text:`开盖后大火收汁，汤汁浓稠后翻匀即可出锅。`,image:e}],tips:`牛蛙要确保熟透，焖煮时间不少于8分钟；泡椒本身有咸味，最后加盐前先尝一下味道。`,coverImage:e},{id:`rec-24`,name:`豆瓣鱼`,difficulty:`medium`,duration:`25分钟`,cuisine:`川菜`,ingredients:[{name:`鲫鱼`,amount:`1条（约500g）`},{name:`豆瓣酱`,amount:`2勺`},{name:`生姜`,amount:`5片`},{name:`大蒜`,amount:`3瓣`},{name:`大葱`,amount:`2根`},{name:`料酒`,amount:`2勺`},{name:`生抽`,amount:`1勺`},{name:`糖`,amount:`半勺`},{name:`淀粉`,amount:`1勺`},{name:`食用油`,amount:`3勺`}],steps:[{order:1,text:`鱼处理干净，两面各划三刀方便入味，用盐和料酒抹匀腌制15分钟，用厨房纸吸干表面水分。`,image:e},{order:2,text:`锅中倒油烧至七成热，轻轻放入鱼，中火煎至两面金黄（每面约3分钟），盛出备用。`,image:e},{order:3,text:`锅中留底油，放入豆瓣酱、姜片、蒜末小火炒出红油，炒出豆瓣的咸香味。`,image:e},{order:4,text:`加入一碗清水、生抽、糖，大火烧开，将煎好的鱼放入锅中，盖上锅盖中火焖8分钟。`,image:e},{order:5,text:`将鱼盛出装盘。锅中汤汁淋入水淀粉勾薄芡，大火收浓，浇在鱼身上，撒上葱花即可。`,image:e}],tips:`煎鱼前鱼身一定要擦干水分，下锅后不要急于翻动，一面煎定型再翻，鱼皮才不会破。`,coverImage:e},{id:`rec-25`,name:`开水白菜`,difficulty:`medium`,duration:`30分钟`,cuisine:`川菜`,ingredients:[{name:`白菜`,amount:`1棵（取菜心）`},{name:`鸡汤`,amount:`500ml`},{name:`火腿`,amount:`30g`},{name:`香菇`,amount:`3朵`},{name:`盐`,amount:`适量`},{name:`料酒`,amount:`1勺`}],steps:[{order:1,text:`白菜取嫩菜心部分，整棵不散开，修整齐。火腿切细丝，香菇泡发切丝。`,image:e},{order:2,text:`锅中烧水加少许盐和料酒，放入白菜心焯水2分钟至微软，捞出沥干，放入大碗中。`,image:e},{order:3,text:`将鸡汤加热至微沸，尝咸淡补盐。鸡汤要清澈见底（如有浑浊可用蛋清澄清）。`,image:e},{order:4,text:`将热鸡汤缓缓倒入盛有白菜的碗中，汤面没过白菜。`,image:e},{order:5,text:`碗上盖保鲜膜或加盖，入蒸锅大火蒸15分钟至白菜酥软入味。出锅后撒上火腿丝和香菇丝点缀。`,image:e}],tips:`这道菜的精华在清汤——鸡汤要足够清澈，看起来像"开水"；白菜心只用最嫩的部分，外层老叶弃用。`,coverImage:e},{id:`rec-26`,name:`糖醋鲤鱼`,difficulty:`medium`,duration:`30分钟`,cuisine:`鲁菜`,ingredients:[{name:`鲤鱼`,amount:`1条（约600g）`},{name:`淀粉`,amount:`100g`},{name:`番茄酱`,amount:`3勺`},{name:`糖`,amount:`3勺`},{name:`醋`,amount:`2勺`},{name:`料酒`,amount:`1勺`},{name:`生姜`,amount:`3片`},{name:`大葱`,amount:`1根`},{name:`食用油`,amount:`适量（炸用）`}],steps:[{order:1,text:`鱼处理干净，在鱼身两面改牡丹花刀（先垂直切入至骨，再横向片开），用盐、料酒、姜葱腌制15分钟。`,image:e},{order:2,text:`用厨房纸吸干鱼身水分，均匀裹上干淀粉，花刀缝隙也要裹到，提起鱼尾抖掉多余粉。`,image:e},{order:3,text:`锅中倒足量油烧至七成热，一手提鱼尾，一手用勺舀热油浇在鱼身上定型，然后整条放入锅中炸至金黄酥脆，捞出控油装盘。`,image:e},{order:4,text:`另起锅，加少许油，放入番茄酱、糖、醋和半碗水，小火熬至糖融化、汁液浓稠冒泡。`,image:e},{order:5,text:`将熬好的糖醋汁均匀浇在炸好的鱼身上，立即上桌。`,image:e}],tips:`鱼身裹粉要均匀，尤其花刀缝隙；糖醋汁熬到能拉丝的状态最合适，趁热浇在鱼上才入味。`,coverImage:e},{id:`rec-27`,name:`葱烧海参`,difficulty:`medium`,duration:`35分钟`,cuisine:`鲁菜`,ingredients:[{name:`海参`,amount:`4只（水发）`},{name:`大葱`,amount:`3根`},{name:`生抽`,amount:`2勺`},{name:`蚝油`,amount:`1勺`},{name:`料酒`,amount:`1勺`},{name:`糖`,amount:`半勺`},{name:`淀粉`,amount:`1勺`},{name:`鸡汤`,amount:`200ml`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`水发海参洗净，从腹部剪开去除内脏和沙嘴，切成条状，放入沸水中焯2分钟捞出。`,image:e},{order:2,text:`大葱只用葱白部分，切5cm长的段，在葱段表面划几刀让葱香更容易释放。`,image:e},{order:3,text:`锅中倒油，放入葱段小火慢煎至葱白表面金黄、葱香浓郁飘出，将葱段盛出备用，锅中留葱油。`,image:e},{order:4,text:`在葱油锅中加入生抽、蚝油、料酒、糖和高汤，大火烧开后放入海参。`,image:e},{order:5,text:`转小火焖烧10分钟让海参入味，然后放入煎好的葱段，淋入水淀粉勾芡，汤汁浓稠即可出锅。`,image:e}],tips:`葱一定要煎到金黄但不要焦，葱油是这道菜的灵魂；海参本身无味，全靠汤汁渗透。`,coverImage:e},{id:`rec-28`,name:`九转大肠`,difficulty:`medium`,duration:`40分钟`,cuisine:`鲁菜`,ingredients:[{name:`猪肉`,amount:`500g`},{name:`糖`,amount:`3勺`},{name:`醋`,amount:`2勺`},{name:`生抽`,amount:`2勺`},{name:`老抽`,amount:`1勺`},{name:`料酒`,amount:`2勺`},{name:`桂皮`,amount:`1小块`},{name:`八角`,amount:`2个`},{name:`生姜`,amount:`5片`},{name:`大葱`,amount:`2根`}],steps:[{order:1,text:`猪大肠翻面，用面粉和白醋反复搓洗去黏液和异味，里外冲洗干净。`,image:e},{order:2,text:`大肠冷水下锅，加姜片、料酒焯水10分钟，捞出洗净，切成2cm长的段。`,image:e},{order:3,text:`锅中倒油，放入糖小火炒出糖色（颜色变为枣红色时），迅速放入大肠段翻炒上色。`,image:e},{order:4,text:`加入生抽、老抽、料酒、桂皮、八角、姜葱，倒入没过食材的水，大火烧开转小火焖30分钟至大肠软烂。`,image:e},{order:5,text:`挑出香料，大火收汁至汤汁浓稠包裹住每块大肠，淋入少许醋翻匀即可装盘。`,image:e}],tips:`洗大肠是关键步骤，面粉揉搓能有效去腥去黏液；炒糖色火候要小，颜色一到位立刻下大肠防止炒苦。`,coverImage:e},{id:`rec-29`,name:`油焖大虾`,difficulty:`easy`,duration:`20分钟`,cuisine:`鲁菜`,ingredients:[{name:`虾`,amount:`500g`},{name:`大葱`,amount:`2根`},{name:`生姜`,amount:`5片`},{name:`生抽`,amount:`2勺`},{name:`糖`,amount:`1勺`},{name:`料酒`,amount:`1勺`},{name:`食用油`,amount:`3勺`}],steps:[{order:1,text:`大虾剪去虾须和虾枪，用牙签从虾背第二节挑出虾线，洗净沥干水分。`,image:e},{order:2,text:`葱切段，姜切片。锅中多倒些油烧至七成热，放入大虾，两面煎至虾壳变红、虾油溢出（约2分钟）。`,image:e},{order:3,text:`用铲子轻压虾头挤出虾脑，放入葱段、姜片炒出香味。`,image:e},{order:4,text:`加入生抽、糖、料酒和2勺清水，盖上锅盖中小火焖3-4分钟让虾充分入味。`,image:e},{order:5,text:`开盖大火收汁至汤汁浓稠挂在虾身上，将虾装盘，剩下的浓汁淋在虾上即可。`,image:e}],tips:`虾头里的虾脑是天然鲜味来源，煎的时候用铲子轻压让它流出；收汁不要太干，留少许汤汁蘸虾肉吃。`,coverImage:e},{id:`rec-30`,name:`锅塌豆腐`,difficulty:`easy`,duration:`15分钟`,cuisine:`鲁菜`,ingredients:[{name:`豆腐`,amount:`1块`},{name:`鸡蛋`,amount:`2个`},{name:`面粉`,amount:`2勺`},{name:`大葱`,amount:`1根`},{name:`生姜`,amount:`2片`},{name:`生抽`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`3勺`}],steps:[{order:1,text:`豆腐切成1cm厚的大片，均匀撒上少许盐腌5分钟。鸡蛋打散加少许盐。葱姜切末。`,image:e},{order:2,text:`每片豆腐先蘸一层面粉，再裹上蛋液，两面都要均匀包裹。`,image:e},{order:3,text:`锅中倒油烧至五成热，将裹好蛋液的豆腐片轻轻放入，中小火煎至两面金黄（每面约2分钟）。`,image:e},{order:4,text:`将锅中多余的油倒出，放入葱姜末煸香，加入生抽和2勺清水，盖上锅盖小火焖3分钟让豆腐入味。`,image:e},{order:5,text:`开盖大火收干汁水，轻轻将豆腐盛出装盘，淋上锅中剩余的浓汁。`,image:e}],tips:`豆腐蘸面粉和蛋液时要轻拿轻放防止碎裂；煎豆腐时不要翻动太频繁，等一面定型再翻。`,coverImage:e},{id:`rec-31`,name:`四喜丸子`,difficulty:`medium`,duration:`40分钟`,cuisine:`鲁菜`,ingredients:[{name:`猪肉`,amount:`400g（三肥七瘦）`},{name:`马蹄`,amount:`5个`},{name:`大葱`,amount:`2根`},{name:`生姜`,amount:`5片`},{name:`鸡蛋`,amount:`1个`},{name:`淀粉`,amount:`2勺`},{name:`生抽`,amount:`2勺`},{name:`老抽`,amount:`1勺`},{name:`料酒`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`适量（炸用）`}],steps:[{order:1,text:`五花肉剁成肉馅（不要太细，保留颗粒感），马蹄去皮切碎丁，葱姜切末。`,image:e},{order:2,text:`肉馅中加入马蹄丁、葱姜末、鸡蛋、淀粉、料酒、盐，顺一个方向搅拌摔打至肉馅上劲起胶。`,image:e},{order:3,text:`双手沾水防粘，将肉馅分成4等份，团成大丸子（直径约5cm），双手来回摔打让丸子紧实。`,image:e},{order:4,text:`锅中倒油烧至六成热，放入丸子中火炸至表面金黄定型（约3分钟），捞出控油。`,image:e},{order:5,text:`另起锅加少许油，放入葱姜爆香，加入生抽、老抽和适量清水，放入丸子大火烧开转小火焖炖20分钟至熟透，收汁装盘。`,image:e}],tips:`肉馅要反复摔打才能让丸子有弹性不散；炸丸子只为定型上色，内部不熟没关系，靠后面炖煮。`,coverImage:e},{id:`rec-32`,name:`滑炒里脊丝`,difficulty:`easy`,duration:`18分钟`,cuisine:`鲁菜`,ingredients:[{name:`猪肉`,amount:`250g`},{name:`木耳`,amount:`50g`},{name:`冬笋`,amount:`100g`},{name:`蛋清`,amount:`1个`},{name:`淀粉`,amount:`2勺`},{name:`盐`,amount:`适量`},{name:`生姜`,amount:`2片`},{name:`大葱`,amount:`1根`},{name:`食用油`,amount:`3勺`}],steps:[{order:1,text:`里脊肉切细丝，加盐、蛋清、淀粉抓匀上浆，腌制10分钟。木耳泡发切丝，冬笋切丝焯水。`,image:e},{order:2,text:`调碗汁：碗中加少许水、盐、淀粉搅匀。姜葱切末。`,image:e},{order:3,text:`锅中倒较多油烧至四成热（低温），放入肉丝用筷子快速拨散，滑炒至肉丝变白立即捞出控油。`,image:e},{order:4,text:`锅中留底油，放入姜葱末爆香，加入木耳丝和笋丝翻炒至断生。`,image:e},{order:5,text:`倒入肉丝，淋入碗汁，大火快速翻炒至芡汁均匀包裹所有食材，出锅装盘。`,image:e}],tips:`滑炒的关键是低温油（四成热约120°C），肉丝下锅快速划散，变色即出，保证嫩滑口感。`,coverImage:e},{id:`rec-33`,name:`爆炒腰花`,difficulty:`medium`,duration:`20分钟`,cuisine:`鲁菜`,ingredients:[{name:`猪肉`,amount:`2个`},{name:`青椒`,amount:`1个`},{name:`木耳`,amount:`50g`},{name:`大蒜`,amount:`3瓣`},{name:`生抽`,amount:`1勺`},{name:`料酒`,amount:`2勺`},{name:`醋`,amount:`半勺`},{name:`淀粉`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`猪腰对半切开，片去中间白色的腰臊（一定要去干净，否则有异味），在表面切十字花刀后切成小块。`,image:e},{order:2,text:`腰花用料酒、少许盐和淀粉抓匀腌制10分钟去腥。青椒切块，木耳撕小朵，蒜切片。`,image:e},{order:3,text:`锅中烧水至微沸，放入腰花焯水10秒至变色卷起，立即捞出过凉水保持脆嫩。`,image:e},{order:4,text:`锅中倒油大火烧热，放入蒜片爆香，加入青椒和木耳大火翻炒至断生。`,image:e},{order:5,text:`倒入腰花快速翻炒，淋入生抽和醋，大火爆炒30秒，加盐调味即可出锅装盘。`,image:e}],tips:`腰臊是猪腰腥味的来源，一定要彻底片除；腰花焯水和爆炒时间都要短，慢了就老了咬不动。`,coverImage:e},{id:`rec-34`,name:`奶汤蒲菜`,difficulty:`easy`,duration:`20分钟`,cuisine:`鲁菜`,ingredients:[{name:`蒲菜`,amount:`200g`},{name:`火腿`,amount:`30g`},{name:`香菇`,amount:`3朵`},{name:`鸡汤`,amount:`500ml`},{name:`生姜`,amount:`2片`},{name:`盐`,amount:`适量`},{name:`料酒`,amount:`1勺`}],steps:[{order:1,text:`蒲菜剥去外层老皮，取嫩茎部分切段，放入沸水中焯1分钟去除涩味，捞出过凉备用。`,image:e},{order:2,text:`火腿切细丝，香菇泡发切丝。姜切丝。`,image:e},{order:3,text:`锅中倒少许油，放入姜丝爆香，加入高汤大火烧开。`,image:e},{order:4,text:`放入焯好的蒲菜段，转中火炖煮5分钟让蒲菜吸收汤汁的鲜味。`,image:e},{order:5,text:`加入火腿丝和香菇丝，加盐和料酒调味，再煮2分钟即可盛入汤碗。`,image:e}],tips:`蒲菜焯水时间不要太长，否则会失去脆嫩口感；高汤本身有鲜味，盐要少放。`,coverImage:e},{id:`rec-35`,name:`炸藕合`,difficulty:`easy`,duration:`18分钟`,cuisine:`鲁菜`,ingredients:[{name:`莲藕`,amount:`1节`},{name:`猪肉`,amount:`150g`},{name:`面粉`,amount:`100g`},{name:`鸡蛋`,amount:`1个`},{name:`大葱`,amount:`1根`},{name:`生姜`,amount:`2片`},{name:`生抽`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`适量（炸用）`}],steps:[{order:1,text:`莲藕去皮洗净，切成0.5cm厚的夹刀片（第一刀不切断，第二刀切断，形成可以夹馅的藕夹）。`,image:e},{order:2,text:`猪肉末加葱姜末、生抽、盐调匀成馅料，填入藕夹中，轻轻按压让馅料均匀分布。`,image:e},{order:3,text:`调面糊：碗中放入面粉、鸡蛋、少许盐和适量清水，搅拌成酸奶稠度的面糊（提起筷子面糊缓慢滴落）。`,image:e},{order:4,text:`锅中倒足量油烧至六成热（放入筷子冒密集小泡），藕夹裹匀面糊，逐一下锅。`,image:e},{order:5,text:`中小火炸至表面金黄酥脆（约3分钟），捞出控油。油温升高后快速复炸30秒让外壳更脆，捞出装盘。`,image:e}],tips:`藕夹的肉馅不要填太多，否则炸的时候容易涨开；复炸是让外皮酥脆的关键，时间很短即可。`,coverImage:e},{id:`rec-36`,name:`白切鸡`,difficulty:`easy`,duration:`25分钟`,cuisine:`粤菜`,ingredients:[{name:`鸡肉`,amount:`1只（约1kg）`},{name:`生姜`,amount:`1大块`},{name:`大葱`,amount:`3根`},{name:`沙姜`,amount:`2块`},{name:`酱油`,amount:`2勺`},{name:`料酒`,amount:`2勺`}],steps:[{order:1,text:`鸡处理干净，锅中加足量水（能没过鸡），放入姜片、葱结、料酒，大火烧开。`,image:e},{order:2,text:`手提鸡颈，将鸡放入沸水中浸10秒后提起，重复三次（这个"三提三浸"让鸡皮收紧、受热均匀）。`,image:e},{order:3,text:`将鸡完全浸入水中，水再次沸腾后关火，盖上锅盖焖20分钟（利用余温浸熟鸡肉，保证肉质嫩滑）。`,image:e},{order:4,text:`捞出鸡放入冰水中浸泡5分钟（皮遇冷收缩变得爽脆），取出斩块装盘。`,image:e},{order:5,text:`制作蘸料：姜葱切成末，加少许盐，淋入滚烫热油激香，再加入沙姜末、酱油调匀即可。`,image:e}],tips:`白切鸡靠"浸"不靠"煮"——关火后利用余温浸熟，这样鸡肉才嫩滑多汁不柴；过冰水是关键，鸡皮会变得爽脆。`,coverImage:e},{id:`rec-37`,name:`清蒸鲈鱼`,difficulty:`easy`,duration:`20分钟`,cuisine:`粤菜`,ingredients:[{name:`鲈鱼`,amount:`1条（约500g）`},{name:`生姜`,amount:`1大块`},{name:`大葱`,amount:`3根`},{name:`酱油`,amount:`3勺`},{name:`料酒`,amount:`1勺`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`鱼处理干净，在鱼身两面各划三刀方便入味，用盐和料酒抹匀腌制10分钟。`,image:e},{order:2,text:`姜一半切片一半切细丝，葱白切段、葱绿切细丝。葱姜丝泡入冷水中使其卷曲美观。`,image:e},{order:3,text:`盘中铺上姜片和葱段，将鱼放在上面（让鱼与盘底有空隙方便蒸汽流通），鱼身上也放姜葱。`,image:e},{order:4,text:`蒸锅水烧开后放入鱼盘，大火蒸8-10分钟（视鱼大小而定），关火后虚蒸1分钟。`,image:e},{order:5,text:`取出鱼盘，倒掉盘中蒸出的腥水和姜葱。重新铺上泡卷的葱姜丝，淋上蒸鱼豉油，最后烧一勺滚烫热油浇在上面激香。`,image:e}],tips:`水开后再放鱼，大火蒸，不要蒸太久（500g鱼8分钟即可）；蒸出的汁水一定要倒掉，那是腥味的来源。`,coverImage:e},{id:`rec-38`,name:`蒜蓉粉丝蒸扇贝`,difficulty:`easy`,duration:`18分钟`,cuisine:`粤菜`,ingredients:[{name:`贝类`,amount:`6只`},{name:`粉丝`,amount:`1小捆`},{name:`大蒜`,amount:`1整头`},{name:`生抽`,amount:`2勺`},{name:`大葱`,amount:`1根`},{name:`食用油`,amount:`3勺`}],steps:[{order:1,text:`粉丝用温水泡软（约15分钟），剪成短段。扇贝洗净，用刀将贝肉与壳分离，去除黑色内脏部分。`,image:e},{order:2,text:`蒜全部切成蒜末，分成两份。锅中倒油，放入一半蒜末小火炸至金黄香酥（金银蒜），关火后混入另一半生蒜末，加生抽调匀。`,image:e},{order:3,text:`将泡软的粉丝铺在扇贝壳底，放上贝肉，在每个扇贝上舀一勺蒜蓉酱。`,image:e},{order:4,text:`蒸锅水开后放入扇贝，大火蒸5分钟即可（贝肉变白即熟）。`,image:e},{order:5,text:`取出扇贝，撒上葱花，另起锅烧一勺热油，逐个淋在扇贝上激出蒜香即可上桌。`,image:e}],tips:`金银蒜（一半炸香一半生蒜）是粤菜蒜蓉系列的灵魂配方，炸蒜提供香气，生蒜提供辛辣层次感。`,coverImage:e},{id:`rec-39`,name:`广东烧鸭`,difficulty:`medium`,duration:`50分钟`,cuisine:`粤菜`,ingredients:[{name:`鸭肉`,amount:`1只（约2kg）`},{name:`五香粉`,amount:`2小勺`},{name:`糖`,amount:`2勺`},{name:`醋`,amount:`2勺`},{name:`生抽`,amount:`3勺`},{name:`老抽`,amount:`1勺`},{name:`生姜`,amount:`5片`},{name:`大蒜`,amount:`5瓣`},{name:`盐`,amount:`1勺`},{name:`料酒`,amount:`2勺`}],steps:[{order:1,text:`鸭处理干净，用开水反复浇淋鸭皮使其收紧，然后用厨房纸彻底吸干水分。`,image:e},{order:2,text:`调腌料：碗中混合五香粉、生抽、老抽、盐、姜蒜末、料酒，均匀涂抹在鸭腔内壁，腌制30分钟。`,image:e},{order:3,text:`用竹签或针线将鸭腔开口缝合，打气或用吸管吹气让皮肉分离（皮会更脆）。`,image:e},{order:4,text:`调脆皮水：麦芽糖加白醋和少许热水搅匀，均匀刷在鸭皮表面。将鸭挂在通风处风干2-3小时至鸭皮完全干爽。`,image:e},{order:5,text:`烤箱预热200°C，鸭胸朝上放入烤盘中，烤40-45分钟至鸭皮枣红酥脆。出炉后斩块装盘。`,image:e}],tips:`风干鸭皮是关键一步，皮不干烤不脆；可用电吹风冷风档加速风干过程。`,coverImage:e},{id:`rec-40`,name:`白灼虾`,difficulty:`easy`,duration:`10分钟`,cuisine:`粤菜`,ingredients:[{name:`虾`,amount:`300g`},{name:`生姜`,amount:`5片`},{name:`大葱`,amount:`2根`},{name:`料酒`,amount:`2勺`},{name:`酱油`,amount:`2勺`},{name:`芥末`,amount:`少许（可选）`}],steps:[{order:1,text:`虾洗净，剪去虾须，用牙签从虾背第二节挑出虾线。姜切片，葱切段。`,image:e},{order:2,text:`锅中加足量水，放入姜片、葱段、料酒，大火烧开。`,image:e},{order:3,text:`水沸后倒入虾，用筷子轻轻拨散，大火煮约2分钟至虾壳变红、虾身弯曲即可。`,image:e},{order:4,text:`立即捞出虾放入冰水中过凉（虾肉遇冷收缩更弹牙），沥干装盘。酱油加芥末作为蘸料一同上桌。`,image:e}],tips:`虾煮的时间很短，变红弯曲即熟，煮久了肉质变老；过冰水是让虾肉弹牙的秘诀。`,coverImage:e},{id:`rec-41`,name:`玉米排骨汤`,difficulty:`easy`,duration:`60分钟`,cuisine:`粤菜`,ingredients:[{name:`猪肉`,amount:`400g`},{name:`玉米`,amount:`2根`},{name:`胡萝卜`,amount:`1根`},{name:`生姜`,amount:`5片`},{name:`盐`,amount:`适量`},{name:`料酒`,amount:`1勺`}],steps:[{order:1,text:`排骨斩小段，冷水下锅加姜片和料酒焯水，水沸后撇去浮沫，捞出排骨用温水洗净。`,image:e},{order:2,text:`玉米剥去外皮切段（每段约3-4cm），胡萝卜去皮切滚刀块。`,image:e},{order:3,text:`砂锅或炖锅中放入排骨、姜片，加足量清水（一次加足，中途不加水），大火烧开。`,image:e},{order:4,text:`转最小火慢炖40分钟，至排骨软烂、汤色微白。`,image:e},{order:5,text:`加入玉米段和胡萝卜块，继续炖20分钟至蔬菜熟透，最后加盐调味即可。`,image:e}],tips:`煲汤水要一次加足，中途加水会破坏汤的鲜味；盐一定要最后放，放早了排骨不容易炖烂。`,coverImage:e},{id:`rec-42`,name:`豉汁蒸排骨`,difficulty:`easy`,duration:`20分钟`,cuisine:`粤菜`,ingredients:[{name:`猪肉`,amount:`300g`},{name:`豆豉`,amount:`2勺`},{name:`大蒜`,amount:`4瓣`},{name:`生抽`,amount:`1勺`},{name:`蚝油`,amount:`1勺`},{name:`糖`,amount:`半勺`},{name:`淀粉`,amount:`2勺`},{name:`食用油`,amount:`1勺`}],steps:[{order:1,text:`排骨斩小块，放入清水中浸泡20分钟去除血水，沥干后加淀粉反复抓揉2分钟，再用清水洗净沥干（这样蒸出来更嫩）。`,image:e},{order:2,text:`豆豉切碎，蒜切末。碗中混合豆豉末、蒜末、生抽、蚝油、糖、淀粉和食用油，搅匀成腌料。`,image:e},{order:3,text:`将腌料倒入排骨中，充分抓拌均匀，腌制15分钟让排骨入味。`,image:e},{order:4,text:`蒸锅水开后，将腌好的排骨平铺在盘中（不要叠放），放入蒸锅大火蒸12分钟至熟透。`,image:e},{order:5,text:`关火后虚蒸1分钟，取出撒上葱花即可上桌。`,image:e}],tips:`淀粉抓揉排骨能去血水并使肉质更嫩滑；排骨平铺不叠放可以保证受热均匀，熟透一致。`,coverImage:e},{id:`rec-43`,name:`滑蛋虾仁`,difficulty:`easy`,duration:`15分钟`,cuisine:`粤菜`,ingredients:[{name:`虾`,amount:`200g`},{name:`鸡蛋`,amount:`4个`},{name:`大葱`,amount:`1根`},{name:`盐`,amount:`适量`},{name:`淀粉`,amount:`1勺`},{name:`食用油`,amount:`3勺`}],steps:[{order:1,text:`虾仁挑去虾线，用少许盐和淀粉抓匀腌制10分钟，然后用清水冲洗干净沥干。`,image:e},{order:2,text:`鸡蛋打散，加少许盐和1勺水淀粉（淀粉+水调匀）搅匀，这样炒出的蛋更嫩滑。葱切葱花。`,image:e},{order:3,text:`锅中倒油烧至七成热，放入虾仁滑炒至变色弯曲，约1分钟即可，盛出备用。`,image:e},{order:4,text:`锅中再加少许油，转中小火，倒入蛋液，待底部略微凝固时放入虾仁。`,image:e},{order:5,text:`用锅铲从锅边往中间轻轻推动蛋液，炒至蛋液八分凝固、仍带湿润感时立刻出锅，撒上葱花。`,image:e}],tips:`炒滑蛋全程中小火，蛋液不能完全炒干，带一点湿润才嫩滑；水淀粉是让蛋更嫩的关键。`,coverImage:e},{id:`rec-44`,name:`蚝油生菜`,difficulty:`easy`,duration:`8分钟`,cuisine:`粤菜`,ingredients:[{name:`生菜`,amount:`1棵`},{name:`蚝油`,amount:`2勺`},{name:`大蒜`,amount:`3瓣`},{name:`生抽`,amount:`半勺`},{name:`糖`,amount:`少许`},{name:`食用油`,amount:`1勺`}],steps:[{order:1,text:`生菜掰开叶片洗净，沥干水分。蒜切末。`,image:e},{order:2,text:`锅中烧大量水至沸腾，加少许油和盐（保持生菜翠绿），放入生菜焯水10秒变软即捞出沥干，铺在盘中。`,image:e},{order:3,text:`小碗中混合蚝油、生抽、糖和2勺清水搅匀成蚝油汁。`,image:e},{order:4,text:`另起锅倒少许油，放入蒜末小火爆香至微黄，倒入蚝油汁煮沸，煮至略微浓稠。`,image:e},{order:5,text:`将熬好的蚝油蒜蓉汁均匀淋在生菜上即可上桌。`,image:e}],tips:`生菜焯水加盐和油可以保持翠绿色；焯水时间极短（10秒），捞出后余温会继续加热。`,coverImage:e},{id:`rec-45`,name:`菠萝咕噜肉`,difficulty:`medium`,duration:`25分钟`,cuisine:`粤菜`,ingredients:[{name:`猪肉`,amount:`300g`},{name:`菠萝`,amount:`半只`},{name:`青椒`,amount:`红绿各半个`},{name:`番茄酱`,amount:`3勺`},{name:`糖`,amount:`2勺`},{name:`醋`,amount:`1勺`},{name:`淀粉`,amount:`适量`},{name:`鸡蛋`,amount:`1个`},{name:`食用油`,amount:`适量（炸用）`}],steps:[{order:1,text:`猪里脊切2cm块，加盐、料酒腌制10分钟，打入鸡蛋抓匀，再逐个裹上干淀粉。`,image:e},{order:2,text:`菠萝去皮去眼切块，用盐水浸泡10分钟去涩。彩椒切块。`,image:e},{order:3,text:`锅中倒油烧至六成热，放入裹好粉的肉块，中小火炸3分钟至金黄，捞出。油温升高后复炸30秒让外皮酥脆。`,image:e},{order:4,text:`调酸甜汁：碗中混合番茄酱、糖、醋和少许清水搅匀。`,image:e},{order:5,text:`锅中留底油，倒入酸甜汁熬至微稠冒泡，放入菠萝块和彩椒翻炒，最后倒入炸好的肉块大火快炒，让每块肉都裹上汁即可出锅。`,image:e}],tips:`肉块复炸是关键，让外壳酥脆不软塌；酸甜汁要熬到冒大泡再放肉块，这样芡汁才能均匀挂住。`,coverImage:e},{id:`rec-46`,name:`腊味煲仔饭`,difficulty:`medium`,duration:`30分钟`,cuisine:`粤菜`,ingredients:[{name:`大米`,amount:`1杯（约150g）`},{name:`腊肠`,amount:`1根`},{name:`腊肉`,amount:`80g`},{name:`鸡蛋`,amount:`1个`},{name:`青菜`,amount:`2棵`},{name:`生抽`,amount:`2勺`},{name:`蚝油`,amount:`1勺`},{name:`糖`,amount:`少许`},{name:`食用油`,amount:`1勺`}],steps:[{order:1,text:`大米提前浸泡30分钟，沥干水分。腊肠和腊肉切薄片。青菜焯水备用。`,image:e},{order:2,text:`砂锅底部和四周刷一层薄油防粘，放入泡好的大米，加清水（米水比约1:1.2），大火烧开。`,image:e},{order:3,text:`水开后转最小火，盖上锅盖煮约8分钟至米面冒大泡、水分基本被吸收。`,image:e},{order:4,text:`在饭面上铺上腊肠片和腊肉片，中间敲入一个鸡蛋，盖上锅盖继续小火焖8分钟。期间沿锅边淋一圈油（这是锅巴的关键）。`,image:e},{order:5,text:`调酱汁：碗中混合生抽、蚝油、糖和少许热水搅匀。关火后焖2分钟，开盖放入青菜，淋入酱汁拌匀即可。`,image:e}],tips:`锅边淋油是形成金黄锅巴的关键；全程小火，闻到焦香味即关火，大火容易烧焦米饭。`,coverImage:e},{id:`rec-47`,name:`姜葱炒蟹`,difficulty:`medium`,duration:`25分钟`,cuisine:`粤菜`,ingredients:[{name:`螃蟹`,amount:`2只`},{name:`生姜`,amount:`1大块`},{name:`大葱`,amount:`4根`},{name:`大蒜`,amount:`3瓣`},{name:`料酒`,amount:`2勺`},{name:`生抽`,amount:`1勺`},{name:`蚝油`,amount:`1勺`},{name:`淀粉`,amount:`2勺`},{name:`食用油`,amount:`3勺`}],steps:[{order:1,text:`梭子蟹洗净，掀开蟹壳去腮去胃，蟹身斩成4-6块，蟹钳用刀背拍裂方便入味。`,image:e},{order:2,text:`蟹块切口处蘸上淀粉（防止蟹黄流失），姜切厚片，葱切长段，蒜拍碎。`,image:e},{order:3,text:`锅中倒油烧至七成热，放入姜片煎至边缘微焦出姜香，再放入蒜瓣和葱白段炒香。`,image:e},{order:4,text:`将蟹块切口面朝下放入锅中，中火煎至蟹壳变红定型，加入料酒翻炒去腥。`,image:e},{order:5,text:`加生抽、蚝油和少许清水，盖上锅盖焖5分钟至蟹肉熟透，开盖大火收汁，放入葱绿段翻匀出锅。`,image:e}],tips:`蟹块切口蘸淀粉能封住蟹黄不流失；姜要多放、煎到微焦，姜的香气是这道菜的灵魂。`,coverImage:e},{id:`rec-48`,name:`脆皮烧肉`,difficulty:`medium`,duration:`40分钟`,cuisine:`粤菜`,ingredients:[{name:`猪肉`,amount:`500g（带皮）`},{name:`盐`,amount:`2小勺`},{name:`五香粉`,amount:`2小勺`},{name:`醋`,amount:`2勺`},{name:`糖`,amount:`1小勺`},{name:`料酒`,amount:`1勺`}],steps:[{order:1,text:`五花肉冷水下锅煮至七成熟（约15分钟），捞出用厨房纸吸干，用叉子在猪皮上密密麻麻扎孔。`,image:e},{order:2,text:`在瘦肉一面均匀涂抹混合好的盐、糖、五香粉和料酒（注意不要碰到猪皮），腌制20分钟。`,image:e},{order:3,text:`用锡纸将五花肉四周包起来，只露出猪皮表面。在猪皮上刷一层白醋（醋让皮更脆），撒一层薄盐。`,image:e},{order:4,text:`烤箱预热220°C，肉放入中层烤40分钟至猪皮鼓起密密麻麻的小泡、变为金黄色。`,image:e},{order:5,text:`取出刮掉表面的盐层，去掉锡纸，再入烤箱250°C烤10分钟让猪皮彻底爆脆。取出稍凉后切片装盘。`,image:e}],tips:`猪皮扎孔越密越好，孔多才能爆出酥脆的皮；白醋刷皮是关键步骤，帮助猪皮脱水起泡。`,coverImage:e},{id:`rec-49`,name:`菜心炒牛肉`,difficulty:`easy`,duration:`15分钟`,cuisine:`粤菜`,ingredients:[{name:`菜心`,amount:`250g`},{name:`牛肉`,amount:`200g`},{name:`生姜`,amount:`3片`},{name:`大蒜`,amount:`2瓣`},{name:`生抽`,amount:`1勺`},{name:`蚝油`,amount:`1勺`},{name:`淀粉`,amount:`1勺`},{name:`糖`,amount:`少许`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`牛肉逆纹切薄片，加生抽、糖、淀粉和少许油抓匀腌制15分钟。菜心洗净切段，姜切丝，蒜切片。`,image:e},{order:2,text:`锅中倒油大火烧热，放入牛肉片滑炒至变色（约30秒），立即盛出备用。`,image:e},{order:3,text:`锅中留底油，放入姜丝蒜片爆香，加入菜心茎部先翻炒30秒。`,image:e},{order:4,text:`再放入菜心叶部翻炒至变软，加蚝油调味。`,image:e},{order:5,text:`倒回牛肉片，大火快速翻炒均匀即可出锅装盘。`,image:e}],tips:`牛肉一定要逆纹切（切断纤维），炒出来才嫩；菜心茎和叶分开下锅，保证同时熟透。`,coverImage:e},{id:`rec-50`,name:`顺德鱼生`,difficulty:`medium`,duration:`25分钟`,cuisine:`粤菜`,ingredients:[{name:`草鱼`,amount:`1条（约1kg，取鱼背肉）`},{name:`柠檬`,amount:`3片`},{name:`生姜`,amount:`1块`},{name:`大葱`,amount:`2根`},{name:`胡萝卜`,amount:`半根`},{name:`花生`,amount:`2勺`},{name:`酱油`,amount:`2勺`},{name:`芥末`,amount:`适量`},{name:`白芝麻`,amount:`1勺`}],steps:[{order:1,text:`草鱼取鱼背两侧的净肉，剥去鱼皮，用厨房纸吸干水分，放入冰箱冷冻30分钟至半硬（便于切薄片）。`,image:e},{order:2,text:`取出鱼肉，用快刀斜片成薄如蝉翼的鱼片（越薄越好），整齐码放在冰盘上。`,image:e},{order:3,text:`柠檬叶、姜、葱、胡萝卜全部切成极细的丝，白芝麻焙香，花生捣碎。`,image:e},{order:4,text:`将各种配菜丝和花生碎、芝麻分小碟装好，酱油加芥末作为蘸料。`,image:e},{order:5,text:`食用时取鱼片蘸酱油芥末，搭配各种配菜丝一起入口，口感清爽鲜甜。`,image:e}],tips:`鱼肉冷冻半硬后更容易片薄；鱼生务必选用新鲜活鱼，且建议选择来源可靠的养殖鱼以减少寄生虫风险。`,coverImage:e},{id:`rec-51`,name:`松鼠桂鱼`,difficulty:`medium`,duration:`35分钟`,cuisine:`苏菜`,ingredients:[{name:`鳜鱼`,amount:`1条（约600g）`},{name:`淀粉`,amount:`150g`},{name:`番茄酱`,amount:`4勺`},{name:`糖`,amount:`3勺`},{name:`醋`,amount:`2勺`},{name:`松子`,amount:`1勺`},{name:`料酒`,amount:`1勺`},{name:`生姜`,amount:`3片`},{name:`食用油`,amount:`适量（炸用）`}],steps:[{order:1,text:`桂鱼去鳞去内脏洗净，切下鱼头。鱼身从脊骨两侧片下鱼肉（尾部相连不切断），在鱼肉上切十字花刀（深至鱼皮但不切断）。`,image:e},{order:2,text:`鱼肉和鱼头用盐、料酒腌制10分钟，然后用厨房纸吸干水分。`,image:e},{order:3,text:`将鱼肉均匀裹上干淀粉，花刀缝隙也要拍满粉，提起鱼尾抖掉多余粉末。`,image:e},{order:4,text:`锅中倒足量油烧至七成热，将鱼肉翻卷成松鼠尾巴状，一手提尾一手用勺定型，放入油锅炸至金黄酥脆。鱼头也炸熟，一起摆盘。`,image:e},{order:5,text:`另起锅，加少许油，放入番茄酱、糖、醋和半碗水，小火熬至浓稠冒大泡，浇在鱼身上，撒上烤香的松子即可。`,image:e}],tips:`花刀要切得密且深但不破皮，这是做出"松鼠毛"效果的关键；炸鱼时油温要够高才能快速定型酥脆。`,coverImage:e},{id:`rec-52`,name:`无锡酱排骨`,difficulty:`medium`,duration:`40分钟`,cuisine:`苏菜`,ingredients:[{name:`猪肉`,amount:`500g`},{name:`糖`,amount:`3勺`},{name:`酱油`,amount:`2勺`},{name:`老抽`,amount:`1勺`},{name:`料酒`,amount:`2勺`},{name:`生姜`,amount:`5片`},{name:`八角`,amount:`2个`},{name:`桂皮`,amount:`1小块`}],steps:[{order:1,text:`排骨斩小段，冷水下锅焯水，水沸后撇去浮沫捞出，用温水洗净沥干。`,image:e},{order:2,text:`锅中倒少许油，放入冰糖小火炒出糖色（颜色变为枣红色时），迅速放入排骨翻炒上色。`,image:e},{order:3,text:`加入姜片、八角、桂皮炒出香味，倒入料酒、酱油、老抽翻炒均匀。`,image:e},{order:4,text:`加入没过排骨的开水，大火烧开转最小火，盖上锅盖焖炖30分钟至排骨酥烂。`,image:e},{order:5,text:`开盖挑出香料，转大火收汁，不停翻动让每块排骨都裹上浓稠的酱汁，汤汁红亮浓稠即可出锅。`,image:e}],tips:`冰糖炒糖色比白糖颜色更红亮；收汁时一定要不停翻动，酱汁浓稠时容易粘锅。`,coverImage:e},{id:`rec-53`,name:`金陵盐水鸭`,difficulty:`medium`,duration:`45分钟`,cuisine:`苏菜`,ingredients:[{name:`鸭肉`,amount:`半只（约1kg）`},{name:`盐`,amount:`3勺`},{name:`花椒`,amount:`2小勺`},{name:`八角`,amount:`3个`},{name:`桂皮`,amount:`1小块`},{name:`生姜`,amount:`5片`},{name:`大葱`,amount:`2根`},{name:`料酒`,amount:`2勺`}],steps:[{order:1,text:`炒锅不放油，放入盐和花椒，小火翻炒至盐微微发黄、花椒飘香，制成花椒盐晾凉。`,image:e},{order:2,text:`鸭身用厨房纸擦干，将花椒盐均匀涂抹在鸭身内外，放入冰箱冷藏腌制4-6小时（最好过夜）。`,image:e},{order:3,text:`取出鸭子，冲洗掉表面的花椒盐。锅中加足量水，放入八角、桂皮、姜片、葱结和料酒，大火烧开。`,image:e},{order:4,text:`将鸭子放入锅中，水再次烧开后撇去浮沫，转最小火保持水面微沸状态煮25分钟。`,image:e},{order:5,text:`关火后让鸭子在汤中浸泡冷却（利用余温让肉更嫩），取出斩块装盘，皮白肉嫩即成。`,image:e}],tips:`花椒盐一定要炒过才香，生花椒没有炒制后的香气；盐水鸭不是大火煮熟的，而是小火浸熟的，肉质才嫩。`,coverImage:e},{id:`rec-54`,name:`扬州狮子头`,difficulty:`medium`,duration:`40分钟`,cuisine:`苏菜`,ingredients:[{name:`猪肉`,amount:`400g（三肥七瘦）`},{name:`马蹄`,amount:`5个`},{name:`大葱`,amount:`2根`},{name:`生姜`,amount:`5片`},{name:`青菜`,amount:`2棵`},{name:`鸡蛋`,amount:`1个`},{name:`淀粉`,amount:`2勺`},{name:`料酒`,amount:`2勺`},{name:`盐`,amount:`适量`}],steps:[{order:1,text:`五花肉先切小粒再剁成肉馅（不要太细，保留米粒大小的颗粒感），马蹄去皮切碎丁，葱姜切末泡水成葱姜水。`,image:e},{order:2,text:`肉馅中加入马蹄丁、葱姜水、鸡蛋、淀粉、料酒、盐，顺一个方向用力搅拌摔打至肉馅上劲粘稠。`,image:e},{order:3,text:`双手沾水防粘，将肉馅团成大丸子（直径约6cm），双手来回摔打使丸子紧实不散。`,image:e},{order:4,text:`锅中倒油烧至六成热，放入丸子中火炸至表面金黄定型（约3分钟），捞出控油。`,image:e},{order:5,text:`砂锅中放入丸子，加入高汤或清水（没过丸子一半即可），大火烧开转小火慢炖30分钟至酥烂，最后放入青菜稍煮即可上桌。`,image:e}],tips:`肉馅的颗粒感是狮子头区别于普通肉丸的关键——要能吃出肉的质感来，不要用绞肉机打成泥。`,coverImage:e},{id:`rec-55`,name:`东坡肉`,difficulty:`medium`,duration:`50分钟`,cuisine:`苏菜`,ingredients:[{name:`猪肉`,amount:`500g（带皮）`},{name:`糖`,amount:`3勺`},{name:`酱油`,amount:`2勺`},{name:`老抽`,amount:`1勺`},{name:`料酒`,amount:`100ml`},{name:`大葱`,amount:`4根`},{name:`生姜`,amount:`5片`}],steps:[{order:1,text:`五花肉切成5cm见方的方块，冷水下锅焯水5分钟，捞出用温水洗净浮沫。`,image:e},{order:2,text:`砂锅底部铺上葱段和姜片（铺满一层防止粘底），将五花肉皮朝下整齐码放。`,image:e},{order:3,text:`加入冰糖、酱油、老抽，倒入料酒和适量开水（汤汁约到肉的一半高度即可）。`,image:e},{order:4,text:`大火烧开后转最小火，盖上锅盖焖炖40分钟。期间将肉翻面，皮朝上继续炖。`,image:e},{order:5,text:`开盖大火收汁，用勺子不断将汤汁浇在肉皮上，直至汤汁浓稠红亮、肉皮呈琥珀色即可装盘，淋上浓汁。`,image:e}],tips:`东坡肉的精髓在于"慢火、少水、足酒"——用料酒代替大部分水去炖，肉质更香；整个过程不翻动肉块，保持完整。`,coverImage:e},{id:`rec-56`,name:`软兜长鱼`,difficulty:`medium`,duration:`25分钟`,cuisine:`苏菜`,ingredients:[{name:`黄鳝`,amount:`300g`},{name:`大蒜`,amount:`5瓣`},{name:`大葱`,amount:`2根`},{name:`酱油`,amount:`2勺`},{name:`老抽`,amount:`半勺`},{name:`糖`,amount:`1勺`},{name:`料酒`,amount:`1勺`},{name:`淀粉`,amount:`1勺`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`黄鳝宰杀洗净，切成5cm长的段，放入沸水中焯30秒至肉质收紧，捞出过凉沥干。`,image:e},{order:2,text:`蒜切片，葱切段。调芡汁：碗中混合酱油、老抽、糖、淀粉和3勺水搅匀。`,image:e},{order:3,text:`锅中倒油大火烧热，放入蒜片和葱段爆香至蒜片微黄。`,image:e},{order:4,text:`倒入黄鳝段大火快炒，加入料酒去腥，翻炒至鳝段卷曲变色。`,image:e},{order:5,text:`淋入调好的芡汁，大火快速翻炒至芡汁浓稠均匀包裹鳝段，出锅装盘。`,image:e}],tips:`鳝鱼焯水时间要短，只是收紧肉质；爆炒全程大火，时间不宜长，保持鳝肉的嫩滑口感。`,coverImage:e},{id:`rec-57`,name:`大煮干丝`,difficulty:`easy`,duration:`20分钟`,cuisine:`苏菜`,ingredients:[{name:`豆干`,amount:`4块`},{name:`火腿`,amount:`30g`},{name:`香菇`,amount:`3朵`},{name:`鸡汤`,amount:`500ml`},{name:`生姜`,amount:`3片`},{name:`盐`,amount:`适量`}],steps:[{order:1,text:`豆腐干切成极细的丝（约2mm粗），火腿切细丝，香菇泡发切细丝。`,image:e},{order:2,text:`锅中烧水至微沸，放入干丝焯水1分钟去除豆腥味，捞出沥干。`,image:e},{order:3,text:`另起锅倒入鸡汤，放入姜片，大火烧开。`,image:e},{order:4,text:`放入焯过水的干丝、香菇丝，转中火煮10分钟让干丝充分吸收鸡汤的鲜味。`,image:e},{order:5,text:`加入火腿丝再煮2分钟，加盐调味（火腿有咸味，盐少放），盛入汤碗。`,image:e}],tips:`干丝切得越细越好，刀工是这道菜的灵魂；鸡汤要用清汤，汤浊了菜品不清爽。`,coverImage:e},{id:`rec-58`,name:`清炖狮子头`,difficulty:`medium`,duration:`40分钟`,cuisine:`苏菜`,ingredients:[{name:`猪肉`,amount:`400g（三肥七瘦）`},{name:`大葱`,amount:`2根`},{name:`生姜`,amount:`5片`},{name:`青菜`,amount:`2棵`},{name:`鸡汤`,amount:`800ml`},{name:`鸡蛋`,amount:`1个`},{name:`淀粉`,amount:`2勺`},{name:`料酒`,amount:`1勺`},{name:`盐`,amount:`适量`}],steps:[{order:1,text:`五花肉切小粒剁成肉馅（保留颗粒感），葱姜切末泡水取葱姜水。`,image:e},{order:2,text:`肉馅加葱姜水、鸡蛋、淀粉、料酒和盐，顺一个方向搅拌摔打上劲。`,image:e},{order:3,text:`双手沾水，将肉馅团成大丸子，双手来回摔打紧实，放入冰箱冷藏20分钟定型。`,image:e},{order:4,text:`砂锅中注入高汤大火烧开，转最小火（保持汤面不翻滚），将丸子轻轻滑入汤中。`,image:e},{order:5,text:`小火慢炖30分钟至肉丸酥烂（汤面始终保持微动不沸），最后放入青菜烫熟，加盐调味即可。`,image:e}],tips:`清炖狮子头不用炸，直接炖；汤面不能滚沸，否则丸子会散——"汤不翻花，肉丸不散"。`,coverImage:e},{id:`rec-59`,name:`桂花糯米藕`,difficulty:`easy`,duration:`30分钟`,cuisine:`苏菜`,ingredients:[{name:`莲藕`,amount:`2节`},{name:`糯米`,amount:`100g`},{name:`糖`,amount:`3勺`},{name:`糖`,amount:`2勺`},{name:`糖`,amount:`2勺`}],steps:[{order:1,text:`糯米提前浸泡4小时以上（最好过夜），沥干水分。莲藕去皮洗净，在顶部切下一小段做"盖子"。`,image:e},{order:2,text:`用筷子将糯米塞入莲藕孔中，边塞边用筷子捅实，装到七八分满（留出糯米膨胀空间）。盖上切下的藕段，用牙签固定。`,image:e},{order:3,text:`锅中放入灌好糯米的藕，加水没过，放入冰糖和红糖，大火烧开。`,image:e},{order:4,text:`转小火煮约30分钟至莲藕软糯，用筷子能轻松插入即可。捞出晾凉。`,image:e},{order:5,text:`切片装盘，将煮藕的糖水大火收浓至糖浆状，淋在藕片上，再浇上桂花糖即可。`,image:e}],tips:`糯米不要填太满，煮的时候会膨胀；煮藕的糖水收浓后就是天然的甜浆，比直接加糖更有层次。`,coverImage:e},{id:`rec-60`,name:`银鱼炒蛋`,difficulty:`easy`,duration:`12分钟`,cuisine:`苏菜`,ingredients:[{name:`银鱼`,amount:`100g`},{name:`鸡蛋`,amount:`3个`},{name:`大葱`,amount:`1根`},{name:`盐`,amount:`适量`},{name:`料酒`,amount:`半勺`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`银鱼洗净沥干水分，用少许料酒和盐抓匀去腥。鸡蛋打散加少许盐搅匀。葱切葱花。`,image:e},{order:2,text:`锅中不放油，小火放入银鱼干煸半分钟去除多余水分，盛出。`,image:e},{order:3,text:`锅中倒油烧至六成热，倒入蛋液，趁蛋液未完全凝固时撒入银鱼。`,image:e},{order:4,text:`用锅铲轻轻推动蛋液，中小火炒至蛋液七八分凝固、仍带湿润感时关火。`,image:e},{order:5,text:`撒上葱花，用余温将蛋烘至全熟但仍嫩滑，出锅装盘。`,image:e}],tips:`银鱼先干煸去水再炒，口感更好不出水；炒蛋八分熟即可关火，余温会让它变全熟但保持嫩滑。`,coverImage:e},{id:`rec-61`,name:`西湖醋鱼`,difficulty:`medium`,duration:`25分钟`,cuisine:`浙菜`,ingredients:[{name:`草鱼`,amount:`1条（约600g）`},{name:`糖`,amount:`3勺`},{name:`醋`,amount:`3勺`},{name:`酱油`,amount:`2勺`},{name:`生姜`,amount:`1大块`},{name:`料酒`,amount:`2勺`},{name:`淀粉`,amount:`1勺`}],steps:[{order:1,text:`草鱼去鳞去内脏洗净，在鱼身两面各划几刀。姜一半切片一半切细丝。`,image:e},{order:2,text:`锅中加足量水，放入姜片和料酒大火烧开，将鱼放入沸水中，转小火保持水微沸状态浸煮6-8分钟至鱼熟。`,image:e},{order:3,text:`小心将鱼捞出放入鱼盘中，保持鱼身完整。姜丝泡水卷曲后摆在鱼身上。`,image:e},{order:4,text:`锅中留少许煮鱼的汤（约半碗），加入糖、醋、酱油，小火熬至糖融化、汁液微稠。`,image:e},{order:5,text:`淋入水淀粉勾薄芡，熬至芡汁透亮浓稠，均匀浇在鱼身上，让糖醋汁包裹整条鱼。`,image:e}],tips:`鱼用浸煮而非大火煮，保持肉质嫩滑不散；糖醋比例约为1:1，突出酸甜平衡的西湖特色。`,coverImage:e},{id:`rec-62`,name:`龙井虾仁`,difficulty:`easy`,duration:`18分钟`,cuisine:`浙菜`,ingredients:[{name:`虾`,amount:`250g`},{name:`龙井茶叶`,amount:`1小勺`},{name:`蛋清`,amount:`1个`},{name:`淀粉`,amount:`2勺`},{name:`料酒`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`3勺`}],steps:[{order:1,text:`虾仁挑去虾线，用盐和淀粉轻轻揉搓后冲洗干净，厨房纸吸干水分。加蛋清、盐、淀粉抓匀上浆，冷藏腌制15分钟。`,image:e},{order:2,text:`龙井茶叶用80°C热水冲泡，泡1分钟后滤出茶汤和茶叶分开备用（茶汤留用，茶叶沥干）。`,image:e},{order:3,text:`锅中倒油烧至四成热（低温，约120°C），放入虾仁快速滑炒，用筷子拨散，虾仁变白弯曲即捞出控油。`,image:e},{order:4,text:`锅中留底油，倒入虾仁，淋入1勺茶汤，加少许盐调味，快速翻炒。`,image:e},{order:5,text:`关火，撒入泡开的龙井茶叶，利用余温翻拌几下让茶香附着在虾仁上，装盘即可。`,image:e}],tips:`虾仁上浆后冷藏能更紧致弹牙；茶汤入菜不要太多，取茶香的清雅而非茶味的苦涩。`,coverImage:e},{id:`rec-63`,name:`叫花鸡`,difficulty:`medium`,duration:`50分钟`,cuisine:`浙菜`,ingredients:[{name:`鸡肉`,amount:`1只（约1.2kg）`},{name:`荷叶`,amount:`2大张（干荷叶泡软）`},{name:`香菇`,amount:`5朵`},{name:`大葱`,amount:`3根`},{name:`生姜`,amount:`5片`},{name:`生抽`,amount:`3勺`},{name:`老抽`,amount:`1勺`},{name:`料酒`,amount:`3勺`},{name:`盐`,amount:`1勺`},{name:`五香粉`,amount:`1小勺`}],steps:[{order:1,text:`鸡处理干净，用盐、生抽、老抽、料酒、五香粉混合成腌料，均匀涂抹鸡身内外，腌制30分钟以上。`,image:e},{order:2,text:`香菇泡发切块，与姜片、葱段一起塞入鸡腹中，用牙签封口。`,image:e},{order:3,text:`泡软的荷叶将整只鸡包裹严实（包两层），再用锡纸包住荷叶外层锁住水分和香气。`,image:e},{order:4,text:`烤箱预热200°C，将包好的鸡放入烤盘中，烤约40分钟至鸡肉熟透。`,image:e},{order:5,text:`取出后打开锡纸和荷叶，香气四溢，鸡肉酥烂脱骨，斩块或手撕装盘，淋上蒸出的原汁。`,image:e}],tips:`荷叶包鸡前要用温水泡软，干荷叶易碎无法包裹；家庭版用锡纸替代传统泥壳，效果同样好且卫生。`,coverImage:e},{id:`rec-64`,name:`宋嫂鱼羹`,difficulty:`medium`,duration:`25分钟`,cuisine:`浙菜`,ingredients:[{name:`鲈鱼`,amount:`1条（约400g）`},{name:`火腿`,amount:`30g`},{name:`香菇`,amount:`3朵`},{name:`鸡蛋`,amount:`1个`},{name:`生姜`,amount:`5片`},{name:`大葱`,amount:`1根`},{name:`淀粉`,amount:`2勺`},{name:`醋`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`料酒`,amount:`1勺`}],steps:[{order:1,text:`鲈鱼去鳞去内脏洗净，鱼身划几刀，盘中铺姜片，放上鱼，淋料酒，入蒸锅大火蒸8分钟至熟。`,image:e},{order:2,text:`鱼晾凉后，用手将鱼肉拆成碎丝（去除鱼刺），火腿和香菇切细丝。`,image:e},{order:3,text:`锅中加入约500ml清水（或用蒸鱼的汤汁+水），放入姜丝大火烧开。`,image:e},{order:4,text:`加入鱼肉丝、香菇丝和火腿丝，转中小火煮3分钟让味道融合。`,image:e},{order:5,text:`加盐调味，淋入水淀粉勾薄芡（汤羹有稠度但不厚），淋入打散的蛋液搅成蛋花，最后加入一勺醋和葱花，搅匀出锅。`,image:e}],tips:`鱼肉拆丝要仔细剔除所有鱼刺；勾芡要薄，像羹不像粥；最后加醋是点睛之笔，突出微微的酸鲜味。`,coverImage:e},{id:`rec-65`,name:`干炸响铃`,difficulty:`easy`,duration:`15分钟`,cuisine:`浙菜`,ingredients:[{name:`豆皮`,amount:`4张`},{name:`猪肉`,amount:`150g`},{name:`面粉`,amount:`2勺`},{name:`大葱`,amount:`1根`},{name:`生姜`,amount:`2片`},{name:`生抽`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`适量（炸用）`}],steps:[{order:1,text:`猪肉末加葱姜末、生抽、盐调味搅拌均匀。面粉加少许水调成糊状作粘合剂。`,image:e},{order:2,text:`豆皮平铺，在一端放上一条肉馅，轻轻卷起成圆柱形卷，末端用面糊封口。`,image:e},{order:3,text:`将卷好的豆皮肉卷斜切成菱形小段（约2cm宽，切面朝上）。`,image:e},{order:4,text:`锅中倒足量油烧至六成热，放入豆皮卷段，中小火炸至表面金黄酥脆（约2分钟）。`,image:e},{order:5,text:`捞出控油装盘。这款菜咬起来有"响铃"般的酥脆声，趁热食用口感最佳。`,image:e}],tips:`豆皮不要卷太紧，松松地卷口感会更酥脆分层；炸的火候不宜太大，慢慢炸透才酥。`,coverImage:e},{id:`rec-66`,name:`荷叶粉蒸肉`,difficulty:`medium`,duration:`30分钟`,cuisine:`浙菜`,ingredients:[{name:`猪肉`,amount:`300g`},{name:`蒸肉粉`,amount:`100g`},{name:`荷叶`,amount:`2张（干荷叶）`},{name:`生抽`,amount:`2勺`},{name:`老抽`,amount:`1勺`},{name:`料酒`,amount:`1勺`},{name:`糖`,amount:`半勺`},{name:`生姜`,amount:`3片`},{name:`大葱`,amount:`1根`}],steps:[{order:1,text:`五花肉切0.5cm厚的薄片，加生抽、老抽、料酒、糖、姜片和葱花抓匀腌制20分钟。`,image:e},{order:2,text:`荷叶用温水泡软，洗净，剪成适合包裹的大小。`,image:e},{order:3,text:`腌好的肉片逐片裹上蒸肉粉，让每片肉都均匀沾满粉。`,image:e},{order:4,text:`荷叶铺在蒸笼或盘中，将裹好粉的肉片整齐码在荷叶上，用荷叶包好。`,image:e},{order:5,text:`蒸锅水开后放入，大火蒸25分钟至肉片软烂、米粉吸足肉汁。取出打开荷叶，香气扑鼻即可。`,image:e}],tips:`蒸肉粉要裹匀，蒸的过程中粉会吸收肉的油脂和汤汁变得软糯入味；荷叶为粉蒸肉增添了清香。`,coverImage:e},{id:`rec-67`,name:`冰糖甲鱼`,difficulty:`medium`,duration:`40分钟`,cuisine:`浙菜`,ingredients:[{name:`甲鱼`,amount:`1只（约500g）`},{name:`糖`,amount:`3勺`},{name:`酱油`,amount:`2勺`},{name:`大葱`,amount:`2根`},{name:`生姜`,amount:`5片`},{name:`料酒`,amount:`3勺`},{name:`淀粉`,amount:`1勺`}],steps:[{order:1,text:`甲鱼宰杀处理干净（建议请摊贩处理），斩成块，冷水下锅加姜片和料酒焯水去腥，捞出洗净。`,image:e},{order:2,text:`锅中倒油，放入冰糖小火慢炒，炒至糖融化变为枣红色时，迅速放入甲鱼块翻炒上色。`,image:e},{order:3,text:`加入葱段、姜片、酱油和料酒，翻炒均匀让甲鱼块裹上调料。`,image:e},{order:4,text:`加入没过甲鱼的开水，大火烧开转最小火，盖上锅盖焖炖25分钟至甲鱼酥烂。`,image:e},{order:5,text:`开盖大火收汁，淋入水淀粉勾薄芡，汤汁浓稠红亮包裹住甲鱼块即可装盘。`,image:e}],tips:`甲鱼一定要新鲜，焯水去腥是关键；冰糖的量要足，才能做出红亮的光泽和甜鲜的味道。`,coverImage:e},{id:`rec-68`,name:`梅干菜扣肉`,difficulty:`medium`,duration:`40分钟`,cuisine:`浙菜`,ingredients:[{name:`猪肉`,amount:`400g（带皮）`},{name:`梅干菜`,amount:`100g`},{name:`糖`,amount:`2勺`},{name:`生抽`,amount:`2勺`},{name:`老抽`,amount:`1勺`},{name:`料酒`,amount:`2勺`},{name:`生姜`,amount:`3片`}],steps:[{order:1,text:`五花肉整块冷水下锅煮至七成熟（约15分钟），捞出趁热在猪皮上均匀涂抹老抽上色，晾凉。`,image:e},{order:2,text:`锅中倒少许油，将五花肉皮朝下放入，中小火煎至猪皮起泡变为深红色（约2分钟），取出晾凉切0.5cm厚片。`,image:e},{order:3,text:`梅干菜用温水泡发洗净，挤干水分，切碎。锅中不放油放入梅干菜，小火干炒出香味，盛出备用。`,image:e},{order:4,text:`取一个大碗，将五花肉片皮朝下整齐码在碗底，上面铺满梅干菜，淋入生抽、料酒、冰糖。`,image:e},{order:5,text:`放入蒸锅大火蒸30分钟至肉片酥烂。取出后倒扣在盘中（梅干菜在底，肉皮在上），将碗中蒸出的汤汁淋在肉上即可。`,image:e}],tips:`猪皮煎过再蒸，皮会变软糯起皱，是扣肉的标志性口感；一定要倒扣装盘才美观。`,coverImage:e},{id:`rec-69`,name:`钱江肉丝`,difficulty:`easy`,duration:`15分钟`,cuisine:`浙菜`,ingredients:[{name:`猪肉`,amount:`250g`},{name:`青椒`,amount:`1个`},{name:`木耳`,amount:`50g`},{name:`蛋清`,amount:`1个`},{name:`淀粉`,amount:`2勺`},{name:`盐`,amount:`适量`},{name:`料酒`,amount:`1勺`},{name:`食用油`,amount:`3勺`}],steps:[{order:1,text:`猪里脊切细丝，加盐、料酒、蛋清、淀粉抓匀上浆腌制10分钟。青椒切丝，木耳泡发切丝。`,image:e},{order:2,text:`锅中倒较多油烧至四成热，放入肉丝滑炒至变色（约20秒），用筷子拨散后立即捞出控油。`,image:e},{order:3,text:`锅中留底油，放入青椒丝和木耳丝大火翻炒至断生。`,image:e},{order:4,text:`倒回肉丝，加少许盐和料酒，大火快速翻炒均匀即可出锅。`,image:e}],tips:`肉丝滑炒油温不宜过高，低温滑出来的肉丝才嫩；这道菜追求清爽，调味不要太重。`,coverImage:e},{id:`rec-70`,name:`三丝敲鱼`,difficulty:`medium`,duration:`25分钟`,cuisine:`浙菜`,ingredients:[{name:`草鱼`,amount:`1条（取鱼背肉约300g）`},{name:`火腿`,amount:`30g`},{name:`香菇`,amount:`3朵`},{name:`青菜`,amount:`2棵`},{name:`淀粉`,amount:`适量（防粘用）`},{name:`生姜`,amount:`3片`},{name:`盐`,amount:`适量`},{name:`料酒`,amount:`1勺`}],steps:[{order:1,text:`草鱼取鱼背净肉，剥去鱼皮，片成厚片。在案板上撒淀粉，将鱼片放在上面，用擀面杖或刀背轻轻敲打成薄片（越薄越好）。`,image:e},{order:2,text:`敲好的鱼片放入沸水中焯5秒至变白，立即捞出放入凉水中过凉，然后切成细丝。`,image:e},{order:3,text:`火腿切丝，香菇泡发切丝，青菜洗净切丝。姜切丝。`,image:e},{order:4,text:`锅中加水或高汤烧开，放入姜丝、香菇丝煮2分钟出香。`,image:e},{order:5,text:`放入鱼肉丝、火腿丝和青菜丝，加盐和料酒调味，煮1分钟即可盛入汤碗。`,image:e}],tips:`敲鱼时淀粉要撒够防止粘连，敲得越薄口感越好；焯水时间极短（几秒即可），鱼片变白立即捞出。`,coverImage:e},{id:`rec-71`,name:`剁椒鱼头`,difficulty:`medium`,duration:`30分钟`,cuisine:`湘菜`,ingredients:[{name:`鱼头`,amount:`1个（约800g，胖头鱼/花鲢）`},{name:`剁椒`,amount:`4勺`},{name:`生姜`,amount:`1大块`},{name:`大葱`,amount:`3根`},{name:`大蒜`,amount:`5瓣`},{name:`料酒`,amount:`2勺`},{name:`酱油`,amount:`2勺`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`鱼头去鳞去鳃，从头顶部劈开但不要劈断（下巴相连展平），用盐和料酒抹匀腌制15分钟。`,image:e},{order:2,text:`姜一半切片一半切末，蒜切末，葱切段和葱花。盘中铺上姜片和葱段，将鱼头展开平铺在上面。`,image:e},{order:3,text:`在鱼头上均匀铺满剁椒，再撒上姜末和蒜末，淋上蒸鱼豉油。`,image:e},{order:4,text:`蒸锅水开后放入鱼头，大火蒸12分钟至鱼眼凸出、鱼肉离骨。`,image:e},{order:5,text:`取出鱼头撒上葱花，另起锅烧一勺滚烫热油淋在剁椒上激香，即可上桌。`,image:e}],tips:`鱼头一定要新鲜，蒸的时间不能长（12分钟即可）；最后淋热油是点睛之笔，把剁椒的香气全部激发出来。`,coverImage:e},{id:`rec-72`,name:`辣椒炒肉`,difficulty:`easy`,duration:`15分钟`,cuisine:`湘菜`,ingredients:[{name:`猪肉`,amount:`300g`},{name:`青椒`,amount:`4个（螺丝椒最佳）`},{name:`大蒜`,amount:`4瓣`},{name:`豆豉`,amount:`1勺`},{name:`生抽`,amount:`1勺`},{name:`老抽`,amount:`半勺`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`猪肉切薄片，肥瘦分开。青椒斜切圈，蒜拍碎。`,image:e},{order:2,text:`锅烧热不放油，先放肥肉片煸炒，中小火把肥油逼出来，炒至肥肉微焦出油。`,image:e},{order:3,text:`加入瘦肉片翻炒至变色，放入蒜瓣和豆豉炒出香味。`,image:e},{order:4,text:`加入生抽和老抽翻炒上色，倒入青椒圈大火快速翻炒。`,image:e},{order:5,text:`炒至青椒表面起虎皮、微微变软，加盐调味（豆豉和生抽有咸味，盐少放），翻匀出锅。`,image:e}],tips:`辣椒炒肉的灵魂是"锅气"——全程大火，青椒要炒到起虎皮才香；用猪油炒比植物油更香。`,coverImage:e},{id:`rec-73`,name:`毛氏红烧肉`,difficulty:`medium`,duration:`40分钟`,cuisine:`湘菜`,ingredients:[{name:`猪肉`,amount:`500g`},{name:`糖`,amount:`2勺`},{name:`酱油`,amount:`2勺`},{name:`干辣椒`,amount:`5个`},{name:`八角`,amount:`2个`},{name:`桂皮`,amount:`1小块`},{name:`生姜`,amount:`5片`},{name:`料酒`,amount:`2勺`}],steps:[{order:1,text:`五花肉切成3cm方块，冷水下锅加姜片和料酒焯水5分钟，捞出温水洗净。`,image:e},{order:2,text:`锅烧热倒少许油，放入冰糖小火炒出糖色（变成枣红色时），迅速放入肉块翻炒上色。`,image:e},{order:3,text:`加入干辣椒、八角、桂皮、姜片炒出香味，倒入酱油和料酒翻炒均匀。`,image:e},{order:4,text:`加入没过肉的开水，大火烧开转最小火，盖上锅盖焖炖35分钟至肉酥烂。`,image:e},{order:5,text:`开盖转大火收汁，不停翻动让汤汁红亮浓稠挂在每块肉上，装盘即可。`,image:e}],tips:`毛氏红烧肉与普通红烧肉的区别在于不放酱油（传统做法用糖色上色）并加入干辣椒；糖色要炒到位，颜色才红亮。`,coverImage:e},{id:`rec-74`,name:`腊味合蒸`,difficulty:`easy`,duration:`25分钟`,cuisine:`湘菜`,ingredients:[{name:`腊肉`,amount:`150g`},{name:`腊肠`,amount:`1根`},{name:`腊鱼`,amount:`100g`},{name:`生姜`,amount:`3片`},{name:`大蒜`,amount:`2瓣`},{name:`豆豉`,amount:`1勺`},{name:`干辣椒`,amount:`3个`}],steps:[{order:1,text:`腊肉、腊肠用温水刷洗干净，腊鱼用温水泡30分钟去咸味。分别切成薄片。`,image:e},{order:2,text:`将三种腊味整齐码放在蒸碗中，铺上姜片、蒜末、豆豉和干辣椒段。`,image:e},{order:3,text:`蒸锅水开后放入蒸碗，大火蒸20分钟至腊味酥软出油。`,image:e},{order:4,text:`取出蒸碗，滗出碗中的汤汁。将腊味倒扣在盘中，淋上蒸出的汤汁即可。`,image:e}],tips:`腊味本身很咸，蒸之前温水浸泡可以去除部分咸味；蒸出的油汁拌饭极香，不要倒掉。`,coverImage:e},{id:`rec-75`,name:`东安子鸡`,difficulty:`medium`,duration:`25分钟`,cuisine:`湘菜`,ingredients:[{name:`鸡肉`,amount:`2个`},{name:`干辣椒`,amount:`5个`},{name:`花椒`,amount:`1小勺`},{name:`醋`,amount:`2勺`},{name:`生姜`,amount:`1大块`},{name:`大葱`,amount:`2根`},{name:`料酒`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`鸡腿冷水下锅，加姜片和料酒煮至熟透（约15分钟），捞出晾凉后斩成小块。`,image:e},{order:2,text:`姜切丝（量要多，这是东安子鸡的特征），干辣椒剪段，葱切段。`,image:e},{order:3,text:`锅中倒油，放入姜丝小火煸炒至姜丝微焦、姜香浓郁。`,image:e},{order:4,text:`加入花椒和干辣椒段炒出香味，倒入鸡块大火翻炒。`,image:e},{order:5,text:`沿锅边淋入醋，加盐调味，大火快速翻炒至醋香融合，撒入葱段翻匀出锅。`,image:e}],tips:`姜丝是这道菜的主角，量要足、要炒到微焦出香；醋要沿锅边淋入，高温激发出醋香而非酸味。`,coverImage:e},{id:`rec-76`,name:`农家小炒肉`,difficulty:`easy`,duration:`15分钟`,cuisine:`湘菜`,ingredients:[{name:`猪肉`,amount:`300g`},{name:`青椒`,amount:`3个`},{name:`大蒜`,amount:`4瓣`},{name:`生姜`,amount:`3片`},{name:`生抽`,amount:`1勺`},{name:`老抽`,amount:`半勺`},{name:`豆豉`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`1勺`}],steps:[{order:1,text:`五花肉切薄片，肥瘦分开。青椒斜切圈，蒜拍碎，姜切片。`,image:e},{order:2,text:`锅烧热不放油，先下肥肉片小火煸出猪油，炒至肥肉卷曲微焦。`,image:e},{order:3,text:`放入瘦肉片翻炒至变色，加入姜片、蒜瓣和豆豉炒香。`,image:e},{order:4,text:`加入生抽和老抽翻炒上色，倒入青椒圈大火快炒至青椒起虎皮。`,image:e},{order:5,text:`尝味后加盐调味（生抽和豆豉已有咸味），大火翻匀即可出锅。`,image:e}],tips:`这道菜用猪油炒最香，所以先煸肥肉出油；螺丝椒比普通青椒更适合，辣味更足、口感更脆。`,coverImage:e},{id:`rec-77`,name:`香干炒肉`,difficulty:`easy`,duration:`12分钟`,cuisine:`湘菜`,ingredients:[{name:`豆干`,amount:`200g`},{name:`猪肉`,amount:`150g`},{name:`青椒`,amount:`2个`},{name:`大蒜`,amount:`3瓣`},{name:`生抽`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`香干切薄片，猪肉切薄片，青椒切块，蒜切片。`,image:e},{order:2,text:`锅中倒油烧热，放入肉片煸炒至变色出油。`,image:e},{order:3,text:`放入蒜片爆香，加入香干片翻炒至表面微黄。`,image:e},{order:4,text:`加入青椒块大火翻炒至断生，加生抽和盐调味，翻炒均匀出锅。`,image:e}],tips:`香干先煎到表面微黄更香；湘菜版香干炒肉可以加少许干辣椒提味。`,coverImage:e},{id:`rec-78`,name:`酸辣鸡杂`,difficulty:`easy`,duration:`15分钟`,cuisine:`湘菜`,ingredients:[{name:`鸡肉`,amount:`300g`},{name:`泡椒`,amount:`5个`},{name:`生姜`,amount:`3片`},{name:`大蒜`,amount:`3瓣`},{name:`青椒`,amount:`2个`},{name:`料酒`,amount:`2勺`},{name:`生抽`,amount:`1勺`},{name:`醋`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`鸡胗去筋膜切花刀或薄片，鸡心对半切开，鸡肝切块。冷水下锅加料酒焯水30秒，捞出沥干。`,image:e},{order:2,text:`泡椒切段，姜蒜切片，青椒切块。`,image:e},{order:3,text:`锅中倒油大火烧热，放入姜蒜片和泡椒段爆香。`,image:e},{order:4,text:`倒入鸡杂大火快炒1分钟，加入料酒去腥，生抽和醋调味。`,image:e},{order:5,text:`加入青椒块翻炒至断生，尝味补盐，大火翻匀即可出锅。`,image:e}],tips:`鸡杂焯水和爆炒都要快，时间长了会老；泡椒和醋提供酸辣味，比例可根据口味调整。`,coverImage:e},{id:`rec-79`,name:`干锅牛蛙`,difficulty:`medium`,duration:`25分钟`,cuisine:`湘菜`,ingredients:[{name:`牛蛙`,amount:`2只`},{name:`洋葱`,amount:`半个`},{name:`干辣椒`,amount:`8个`},{name:`生姜`,amount:`3片`},{name:`大蒜`,amount:`5瓣`},{name:`豆瓣酱`,amount:`1勺`},{name:`生抽`,amount:`1勺`},{name:`料酒`,amount:`1勺`},{name:`淀粉`,amount:`1勺`},{name:`食用油`,amount:`3勺`},{name:`香菜`,amount:`适量`}],steps:[{order:1,text:`牛蛙宰杀洗净斩块，加料酒、生抽、淀粉抓匀腌制15分钟。洋葱切块，干辣椒剪段，姜蒜切片。`,image:e},{order:2,text:`锅中倒油烧至六成热，放入牛蛙块滑炒至表面金黄定型（约2分钟），盛出备用。`,image:e},{order:3,text:`锅中留底油，放入姜蒜片、干辣椒段、豆瓣酱小火炒出红油和香味。`,image:e},{order:4,text:`加入洋葱块翻炒至半透明，倒入牛蛙块翻炒均匀。`,image:e},{order:5,text:`加2勺清水，盖上锅盖小火焖3分钟入味，开盖大火收汁，撒上香菜即可。`,image:e}],tips:`牛蛙先滑炒再焖，外香里嫩；干锅菜不用太多汤汁，最后收干到微焦的状态最香。`,coverImage:e},{id:`rec-80`,name:`孜然牛肉`,difficulty:`easy`,duration:`18分钟`,cuisine:`湘菜`,ingredients:[{name:`牛肉`,amount:`250g`},{name:`孜然`,amount:`2小勺`},{name:`干辣椒`,amount:`5个`},{name:`洋葱`,amount:`半个`},{name:`料酒`,amount:`1勺`},{name:`生抽`,amount:`1勺`},{name:`淀粉`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`3勺`}],steps:[{order:1,text:`牛肉逆纹切薄片，加料酒、生抽、淀粉和少许油抓匀腌制15分钟。洋葱切丝。`,image:e},{order:2,text:`干辣椒剪段。锅中倒油烧至六成热，放入牛肉片滑炒至变色，盛出备用。`,image:e},{order:3,text:`锅中留底油，放入干辣椒段和洋葱丝大火翻炒至洋葱变软出香。`,image:e},{order:4,text:`倒回牛肉片，撒入孜然粉和盐，大火快速翻炒均匀。`,image:e},{order:5,text:`炒至孜然香气扑鼻、牛肉均匀裹上调料，出锅装盘。`,image:e}],tips:`牛肉逆纹切是关键（切断纤维），炒出来才嫩；孜然要最后放，炒久了香味会挥发。`,coverImage:e},{id:`rec-81`,name:`剁椒蒸排骨`,difficulty:`easy`,duration:`20分钟`,cuisine:`湘菜`,ingredients:[{name:`猪肉`,amount:`300g`},{name:`剁椒`,amount:`3勺`},{name:`大蒜`,amount:`4瓣`},{name:`生抽`,amount:`1勺`},{name:`料酒`,amount:`1勺`},{name:`淀粉`,amount:`1勺`},{name:`食用油`,amount:`1勺`}],steps:[{order:1,text:`排骨斩小块，用清水浸泡20分钟去除血水，沥干。蒜切末。`,image:e},{order:2,text:`排骨加剁椒、蒜末、生抽、料酒、淀粉和食用油抓匀腌制15分钟。`,image:e},{order:3,text:`将腌好的排骨平铺在盘中（不要叠放），蒸锅水开后放入。`,image:e},{order:4,text:`大火蒸12分钟至排骨熟透、肉质嫩滑。关火虚蒸1分钟后取出即可。`,image:e}],tips:`排骨平铺不叠放保证受热均匀；剁椒本身有咸味，不需要额外加盐。`,coverImage:e},{id:`rec-82`,name:`攸县香干`,difficulty:`easy`,duration:`10分钟`,cuisine:`湘菜`,ingredients:[{name:`豆干`,amount:`200g`},{name:`青椒`,amount:`2个`},{name:`大蒜`,amount:`3瓣`},{name:`腊肉`,amount:`50g`},{name:`生抽`,amount:`1勺`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`香干切薄片，腊肉切小片（用肥的部分出油），青椒切圈，蒜切片。`,image:e},{order:2,text:`锅烧热放少许油，放入腊肉片煸炒出油至微焦，盛出腊肉渣（保留腊油在锅中）。`,image:e},{order:3,text:`放入香干片中小火煎至两面微黄起泡，放入蒜片炒香。`,image:e},{order:4,text:`加入青椒圈大火翻炒至断生，倒回腊肉渣，淋入生抽翻炒均匀出锅。`,image:e}],tips:`香干一定要煎到表面起泡才香；腊肉主要是取它的油脂和咸香，不用放很多肉。`,coverImage:e},{id:`rec-83`,name:`猪肉`,difficulty:`easy`,duration:`20分钟`,cuisine:`湘菜`,ingredients:[{name:`猪肉`,amount:`2个`},{name:`青椒`,amount:`2个`},{name:`大蒜`,amount:`3瓣`},{name:`生抽`,amount:`1勺`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`猪血丸子用温水刷洗干净，切成0.5cm厚的片。青椒切块，蒜切片。`,image:e},{order:2,text:`锅烧热倒油，放入猪血丸子片，中小火煎至两面微焦、表面起泡。`,image:e},{order:3,text:`放入蒜片炒出香味，加入青椒块大火翻炒至断生。`,image:e},{order:4,text:`淋入生抽调味，翻炒均匀即可出锅（猪血丸子本身有咸味，不用加盐）。`,image:e}],tips:`猪血丸子本身是腌制品有咸味，调味时要轻；煎的时间要够，煎到表面微焦才香。`,coverImage:e},{id:`rec-84`,name:`蒜蓉辣椒蒸茄子`,difficulty:`easy`,duration:`15分钟`,cuisine:`湘菜`,ingredients:[{name:`茄子`,amount:`2根`},{name:`大蒜`,amount:`5瓣`},{name:`剁椒`,amount:`2勺`},{name:`生抽`,amount:`1勺`},{name:`食用油`,amount:`2勺`},{name:`大葱`,amount:`1根`}],steps:[{order:1,text:`茄子洗净切成粗条（不去皮），整齐码放在盘中。蒜切末，葱切葱花。`,image:e},{order:2,text:`锅中倒油，放入一半蒜末小火炸至金黄，关火混入另一半生蒜末制成金银蒜。`,image:e},{order:3,text:`将剁椒铺在茄条上，再铺上蒜蓉，淋上生抽。`,image:e},{order:4,text:`蒸锅水开后放入，大火蒸10分钟至茄子软烂。`,image:e},{order:5,text:`取出撒上葱花，另起锅烧一勺滚烫热油淋在上面激香即可。`,image:e}],tips:`茄子皮含有花青素不去皮更有营养；金银蒜让蒜香层次更丰富。`,coverImage:e},{id:`rec-85`,name:`酸萝卜炒肚丝`,difficulty:`medium`,duration:`20分钟`,cuisine:`湘菜`,ingredients:[{name:`猪肉`,amount:`1个`},{name:`酸萝卜`,amount:`100g`},{name:`干辣椒`,amount:`5个`},{name:`生姜`,amount:`3片`},{name:`大蒜`,amount:`3瓣`},{name:`料酒`,amount:`2勺`},{name:`生抽`,amount:`1勺`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`猪肚用面粉和盐反复搓洗去黏液，冷水下锅加料酒和姜片焯水10分钟，捞出晾凉切丝。`,image:e},{order:2,text:`酸萝卜切丝（市售或自制），干辣椒剪段，姜蒜切片。`,image:e},{order:3,text:`锅中倒油烧热，放入姜蒜片和干辣椒段爆香。`,image:e},{order:4,text:`倒入猪肚丝大火翻炒2分钟，加入料酒去腥。`,image:e},{order:5,text:`加入酸萝卜丝翻炒均匀，淋入生抽调味，大火快炒至酸辣味融合出锅。`,image:e}],tips:`猪肚一定要用面粉揉搓才能彻底去腥；酸萝卜自带咸酸味，最后调味前先尝味再决定加盐量。`,coverImage:e},{id:`rec-86`,name:`佛跳墙`,difficulty:`hard`,duration:`90分钟`,cuisine:`闽菜`,ingredients:[{name:`海参`,amount:`2只（水发）`},{name:`贝类`,amount:`4只`},{name:`贝类`,amount:`20g`},{name:`鸡汤`,amount:`800ml`},{name:`鸡肉`,amount:`200g`},{name:`猪肉`,amount:`200g`},{name:`香菇`,amount:`5朵`},{name:`火腿`,amount:`30g`},{name:`生姜`,amount:`5片`},{name:`料酒`,amount:`3勺`}],steps:[{order:1,text:`干贝、香菇提前泡发。海参去内脏洗净切条，鲍鱼刷洗干净。鸡肉和排骨斩块焯水去血沫。`,image:e},{order:2,text:`将所有肉类食材分别焯水处理：海参焯水1分钟，鲍鱼焯水30秒。`,image:e},{order:3,text:`取炖盅或砂锅，底层铺姜片和排骨，中层放鸡肉、火腿片和香菇，上层放海参、鲍鱼和干贝。`,image:e},{order:4,text:`倒入高汤（约八分满），加料酒，盖上盖子密封严密（可用保鲜膜封口再加盖）。`,image:e},{order:5,text:`放入蒸锅或炖锅，隔水小火慢炖60分钟以上至所有食材软烂入味、汤汁浓郁醇厚。开盖后加盐调味即可享用。`,image:e}],tips:`佛跳墙的精髓在于"慢煨"——时间越长越入味，隔水炖比直接煮更能保持各食材的原味。家庭版可简化食材，用鸡、排骨、香菇、干贝就足够鲜美。`,coverImage:e},{id:`rec-87`,name:`荔枝肉`,difficulty:`easy`,duration:`18分钟`,cuisine:`闽菜`,ingredients:[{name:`猪肉`,amount:`300g`},{name:`淀粉`,amount:`100g`},{name:`番茄酱`,amount:`3勺`},{name:`糖`,amount:`2勺`},{name:`醋`,amount:`1勺`},{name:`料酒`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`适量（炸用）`}],steps:[{order:1,text:`猪里脊切2cm厚的片，在表面切十字花刀（深至2/3不切断），然后切成菱形小块，加盐和料酒腌制10分钟。`,image:e},{order:2,text:`将肉块均匀裹上干淀粉，花刀缝隙也要裹到，抖掉多余粉。`,image:e},{order:3,text:`锅中倒油烧至六成热，放入肉块中小火炸至表面金黄、花刀绽开形似荔枝外壳，捞出控油。`,image:e},{order:4,text:`调荔枝汁：碗中混合番茄酱、糖、醋和少许清水搅匀。另起锅倒入调好的汁，小火熬至浓稠冒泡。`,image:e},{order:5,text:`倒入炸好的肉块，大火快速翻炒让每块肉都裹上红亮的荔枝汁，出锅装盘。`,image:e}],tips:`花刀要切得深且均匀，炸出来才能像荔枝壳；酸甜汁熬到浓稠再放肉，才能完美挂汁。`,coverImage:e},{id:`rec-88`,name:`海蛎煎`,difficulty:`easy`,duration:`15分钟`,cuisine:`闽菜`,ingredients:[{name:`贝类`,amount:`200g`},{name:`鸡蛋`,amount:`2个`},{name:`淀粉`,amount:`4勺`},{name:`大葱`,amount:`2根`},{name:`盐`,amount:`适量`},{name:`胡椒粉`,amount:`少许`},{name:`食用油`,amount:`3勺`},{name:`甜辣酱`,amount:`适量（蘸料）`}],steps:[{order:1,text:`海蛎用清水轻轻漂洗干净，沥干水分（不要用力搓洗避免破肚）。葱切葱花。`,image:e},{order:2,text:`大碗中放入海蛎，加入地瓜粉、鸡蛋、葱花、盐和白胡椒粉，轻轻拌匀成糊状。`,image:e},{order:3,text:`平底锅倒油烧至八成热，将海蛎糊倒入锅中，用铲子摊平成圆饼状。`,image:e},{order:4,text:`中小火煎至底面金黄酥脆（约3分钟），然后翻面继续煎另一面至金黄。`,image:e},{order:5,text:`两面煎至金黄酥脆，出锅装盘，搭配甜辣酱食用。`,image:e}],tips:`地瓜粉是海蛎煎的灵魂，用其他淀粉口感不同；煎的时候油要够多才能煎出酥脆的边缘。`,coverImage:e},{id:`rec-89`,name:`醉排骨`,difficulty:`easy`,duration:`18分钟`,cuisine:`闽菜`,ingredients:[{name:`猪肉`,amount:`300g`},{name:`淀粉`,amount:`100g`},{name:`糖`,amount:`2勺`},{name:`醋`,amount:`2勺`},{name:`大蒜`,amount:`4瓣`},{name:`生抽`,amount:`1勺`},{name:`料酒`,amount:`1勺`},{name:`食用油`,amount:`适量（炸用）`}],steps:[{order:1,text:`排骨斩小块，加料酒和少许盐腌制15分钟，均匀裹上干淀粉。`,image:e},{order:2,text:`锅中倒油烧至六成热，放入排骨中小火炸至金黄酥脆（约4分钟），捞出。油温升高后复炸30秒。`,image:e},{order:3,text:`蒜切末。碗中混合糖、醋、生抽和蒜末调成醉汁。`,image:e},{order:4,text:`将炸好的排骨趁热倒入醉汁中，快速翻拌让每块排骨都均匀裹上汁。`,image:e},{order:5,text:`装盘后将碗底多余的醉汁淋在排骨上即可。趁热食用，外酥里嫩。`,image:e}],tips:`排骨一定要复炸，这样外皮才会酥脆不软塌；醉汁的糖醋比例可根据口味调整。`,coverImage:e},{id:`rec-90`,name:`南煎肝`,difficulty:`easy`,duration:`15分钟`,cuisine:`闽菜`,ingredients:[{name:`猪肉`,amount:`250g`},{name:`大蒜`,amount:`3瓣`},{name:`生姜`,amount:`3片`},{name:`生抽`,amount:`1勺`},{name:`醋`,amount:`半勺`},{name:`糖`,amount:`1勺`},{name:`料酒`,amount:`1勺`},{name:`淀粉`,amount:`2勺`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`猪肝切薄片（约3mm厚），放入清水中浸泡15分钟去除血水，捞出用厨房纸吸干水分。`,image:e},{order:2,text:`猪肝片加料酒、盐、淀粉抓匀腌制10分钟。姜蒜切末。调碗汁：碗中混合生抽、醋、糖、淀粉和2勺水搅匀。`,image:e},{order:3,text:`锅中倒油大火烧至七成热，放入猪肝片快速滑炒，猪肝变色（约30秒）立即盛出。`,image:e},{order:4,text:`锅中留底油，放入姜蒜末爆香，倒入碗汁熬至冒泡变稠。`,image:e},{order:5,text:`倒回猪肝片，大火快速翻炒至芡汁均匀包裹每片猪肝，即可出锅装盘。`,image:e}],tips:`猪肝一定要切薄、炒快——整道菜爆炒时间不超过1分钟，猪肝嫩滑不老的关键就在速度。`,coverImage:e},{id:`rec-91`,name:`淡糟香螺片`,difficulty:`medium`,duration:`20分钟`,cuisine:`闽菜`,ingredients:[{name:`贝类`,amount:`300g`},{name:`红糟`,amount:`2勺`},{name:`生姜`,amount:`3片`},{name:`大葱`,amount:`2根`},{name:`料酒`,amount:`1勺`},{name:`糖`,amount:`半勺`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`香螺去壳取肉，去除内脏，洗净后切成薄片。放入沸水中焯水10秒立即捞出过凉。`,image:e},{order:2,text:`红糟用少许料酒调稀。姜切片，葱切段。`,image:e},{order:3,text:`锅中倒油烧热，放入姜片爆香，加入调稀的红糟小火炒出糟香。`,image:e},{order:4,text:`转大火，倒入螺片快速翻炒30秒，加入糖和盐调味。`,image:e},{order:5,text:`放入葱段翻匀，立即出锅（螺片炒久了会老韧）。`,image:e}],tips:`螺片焯水和爆炒时间都以秒计，稍长就会变韧；红糟是闽菜独特调味品，需小火炒香才能激发糟香。`,coverImage:e},{id:`rec-92`,name:`鸡汤汆海蚌`,difficulty:`easy`,duration:`15分钟`,cuisine:`闽菜`,ingredients:[{name:`贝类`,amount:`300g`},{name:`鸡汤`,amount:`500ml`},{name:`火腿`,amount:`20g`},{name:`香菇`,amount:`2朵`},{name:`生姜`,amount:`2片`},{name:`盐`,amount:`适量`}],steps:[{order:1,text:`海蚌用刷子刷洗干净外壳，放入清水中加少许盐养1小时吐沙。`,image:e},{order:2,text:`鸡汤加热至微沸，放入姜片、火腿丝和香菇丝煮出香味，加盐调味。`,image:e},{order:3,text:`将海蚌放入沸水中汆烫30秒至壳张开，立即捞出放入汤碗中。`,image:e},{order:4,text:`将滚烫的鸡汤直接浇在海蚌上即可上桌，海蚌的鲜味瞬间融入汤中。`,image:e}],tips:`海蚌汆烫时间极短，壳一张开就捞出；鸡汤要滚烫地浇上去，利用热度让海蚌在碗中达到最佳熟度。`,coverImage:e},{id:`rec-93`,name:`姜母鸭`,difficulty:`medium`,duration:`40分钟`,cuisine:`闽菜`,ingredients:[{name:`鸭肉`,amount:`半只（约1kg）`},{name:`生姜`,amount:`150g（用量要大）`},{name:`香油`,amount:`3勺`},{name:`酱油`,amount:`2勺`},{name:`料酒`,amount:`3勺`},{name:`糖`,amount:`1勺`}],steps:[{order:1,text:`鸭斩块冷水下锅焯水去血沫，捞出洗净沥干。老姜洗刷干净，连皮切成厚片（姜的量一定要足）。`,image:e},{order:2,text:`砂锅或炖锅中倒入麻油，放入老姜片小火慢煎，煎至姜片金黄卷曲、姜香浓郁。`,image:e},{order:3,text:`放入鸭块大火翻炒至表面金黄，鸭皮出油。`,image:e},{order:4,text:`加入酱油、料酒和糖翻炒上色，倒入没过鸭块的热水，大火烧开。`,image:e},{order:5,text:`转最小火盖上锅盖焖炖30分钟至鸭肉酥烂，开盖大火收汁至汤汁浓稠即可。`,image:e}],tips:`姜母鸭的灵魂在于老姜和麻油，姜量不能少、一定要煎到金黄出香；麻油不耐高温，全程火候控制在中小火。`,coverImage:e},{id:`rec-94`,name:`沙茶牛肉`,difficulty:`easy`,duration:`18分钟`,cuisine:`闽菜`,ingredients:[{name:`牛肉`,amount:`250g`},{name:`沙茶酱`,amount:`2勺`},{name:`洋葱`,amount:`半个`},{name:`青椒`,amount:`1个`},{name:`淀粉`,amount:`1勺`},{name:`生抽`,amount:`1勺`},{name:`料酒`,amount:`1勺`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`牛肉逆纹切薄片，加料酒、生抽、淀粉和少许油抓匀腌制15分钟。洋葱和青椒切块。`,image:e},{order:2,text:`沙茶酱用少许温水调稀备用。`,image:e},{order:3,text:`锅中倒油烧至六成热，放入牛肉片滑炒至变色，盛出备用。`,image:e},{order:4,text:`锅中留底油，放入洋葱块炒至半透明出香，加入青椒翻炒至断生。`,image:e},{order:5,text:`倒回牛肉片，淋入调稀的沙茶酱，大火快速翻炒均匀即可出锅。`,image:e}],tips:`沙茶酱本身有咸味和香料味，不需额外加太多调料；牛肉滑炒变色即可，不要炒老。`,coverImage:e},{id:`rec-95`,name:`莆田卤面`,difficulty:`easy`,duration:`20分钟`,cuisine:`闽菜`,ingredients:[{name:`面条`,amount:`200g（鲜面最佳）`},{name:`虾`,amount:`100g`},{name:`香菇`,amount:`4朵`},{name:`猪肉`,amount:`100g`},{name:`青菜`,amount:`2棵`},{name:`生抽`,amount:`1勺`},{name:`蚝油`,amount:`1勺`},{name:`生姜`,amount:`2片`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`虾仁挑虾线，五花肉切薄片，香菇泡发切丝，青菜洗净切段，姜切丝。`,image:e},{order:2,text:`锅中倒油，放入五花肉片煸炒出油至微焦，加入姜丝和香菇丝炒香。`,image:e},{order:3,text:`加入虾仁翻炒至变红，倒入生抽和蚝油翻炒上色。`,image:e},{order:4,text:`加入足量清水（约500ml）大火烧开，放入面条，用筷子拨散防止粘连。`,image:e},{order:5,text:`煮约3分钟至面条断生，加入青菜煮软，汤汁收浓至微稠，尝味补盐，出锅装碗。`,image:e}],tips:`莆田卤面的特色是汤汁浓稠、面条入味——煮面时水量要比普通汤面少，煮出来的面带浓汁才正宗。`,coverImage:e},{id:`rec-96`,name:`臭鳜鱼`,difficulty:`medium`,duration:`30分钟`,cuisine:`徽菜`,ingredients:[{name:`鳜鱼`,amount:`1条（约500g）`},{name:`生姜`,amount:`5片`},{name:`大蒜`,amount:`5瓣`},{name:`干辣椒`,amount:`5个`},{name:`生抽`,amount:`2勺`},{name:`老抽`,amount:`半勺`},{name:`料酒`,amount:`2勺`},{name:`糖`,amount:`半勺`},{name:`大葱`,amount:`2根`},{name:`食用油`,amount:`3勺`}],steps:[{order:1,text:`鳜鱼去鳞去内脏洗净（传统做法用淡盐水腌制发酵产生特殊风味，家庭版可用鲜鱼），鱼身两面各划三刀，用盐和料酒腌制15分钟。`,image:e},{order:2,text:`用厨房纸吸干鱼身水分。姜蒜切片，干辣椒剪段，葱切段。`,image:e},{order:3,text:`锅中倒油烧至七成热，放入鱼，中火煎至两面金黄（每面约3分钟），盛出备用。`,image:e},{order:4,text:`锅中留底油，放入姜片、蒜片和干辣椒段爆香，加入生抽、老抽、料酒、糖和半碗水。`,image:e},{order:5,text:`将煎好的鱼放回锅中，汤汁浇在鱼身上，盖上锅盖中小火焖烧10分钟至鱼入味，大火收汁，撒上葱段出锅。`,image:e}],tips:`传统臭鳜鱼需要提前发酵产生特殊风味，家庭版用鲜鳜鱼做成红烧口味同样美味；煎鱼时一定要擦干水分，一面煎定型再翻面。`,coverImage:e},{id:`rec-97`,name:`黄山炖鸽`,difficulty:`medium`,duration:`40分钟`,cuisine:`徽菜`,ingredients:[{name:`鸽子`,amount:`1只`},{name:`火腿`,amount:`30g`},{name:`香菇`,amount:`5朵`},{name:`鸡汤`,amount:`800ml`},{name:`生姜`,amount:`5片`},{name:`料酒`,amount:`2勺`},{name:`盐`,amount:`适量`},{name:`枸杞`,amount:`少许（可选）`}],steps:[{order:1,text:`鸽子处理干净，斩块，冷水下锅加姜片和料酒焯水去血沫，捞出温水洗净。`,image:e},{order:2,text:`火腿切片，香菇泡发去蒂。枸杞用温水泡发。`,image:e},{order:3,text:`将鸽块、火腿片、香菇和姜片放入炖盅，加入高汤（约八分满）。`,image:e},{order:4,text:`盖上盖子密封（可用保鲜膜封口），放入蒸锅或炖锅，隔水小火炖30分钟至鸽肉酥烂。`,image:e},{order:5,text:`出锅前5分钟加入枸杞，加盐调味，再炖片刻即可。汤色清澈鲜美。`,image:e}],tips:`隔水炖比直接煮更能保持汤清味纯；鸽子容易炖烂，30分钟足够。`,coverImage:e},{id:`rec-98`,name:`虎皮毛豆腐`,difficulty:`easy`,duration:`15分钟`,cuisine:`徽菜`,ingredients:[{name:`豆腐`,amount:`4块`},{name:`干辣椒`,amount:`3个`},{name:`大蒜`,amount:`3瓣`},{name:`酱油`,amount:`1勺`},{name:`大葱`,amount:`1根`},{name:`食用油`,amount:`3勺`}],steps:[{order:1,text:`毛豆腐表面有一层白色绒毛（发酵产生的有益菌丝），用清水轻轻冲洗一下，沥干切块。`,image:e},{order:2,text:`干辣椒剪段，蒜切片，葱切葱花。`,image:e},{order:3,text:`平底锅倒油烧至六成热，将毛豆腐块放入，中小火煎至两面金黄、表面起"虎皮"纹路。`,image:e},{order:4,text:`放入干辣椒段和蒜片煸出香味，淋入酱油，轻轻翻匀让每块豆腐裹上酱色。`,image:e},{order:5,text:`撒上葱花，大火翻炒几下即可出锅。毛豆腐外皮酥脆、内里柔软。`,image:e}],tips:`毛豆腐表面白毛是天然发酵产物，安全可食用；煎的时候油要多、火候要中小火，慢慢煎至虎皮色才好看又好吃。`,coverImage:e},{id:`rec-99`,name:`蜜汁红芋`,difficulty:`easy`,duration:`15分钟`,cuisine:`徽菜`,ingredients:[{name:`红薯`,amount:`2个（约400g）`},{name:`糖`,amount:`3勺`},{name:`蜂蜜`,amount:`2勺`},{name:`食用油`,amount:`适量（炸用）`}],steps:[{order:1,text:`红薯去皮切成滚刀块，放入清水中浸泡5分钟去除表面淀粉，沥干水分。`,image:e},{order:2,text:`锅中倒足量油烧至五成热，放入红薯块中小火炸至表面金黄、竹签能轻松插入（约5分钟），捞出控油。`,image:e},{order:3,text:`另起锅加少许水和冰糖，小火熬至冰糖完全融化、糖水微黄冒泡。`,image:e},{order:4,text:`放入炸好的红薯块快速翻炒，让每块红薯都裹上糖液，然后淋入蜂蜜翻匀即可出锅装盘。`,image:e}],tips:`红薯不要炸太久，表面金黄即可；蜜汁熬到微稠状态再放红薯，裹汁效果最好。`,coverImage:e},{id:`rec-100`,name:`胡适一品锅`,difficulty:`medium`,duration:`50分钟`,cuisine:`徽菜`,ingredients:[{name:`鸡肉`,amount:`半只`},{name:`猪肉`,amount:`200g`},{name:`蛋饺`,amount:`6个`},{name:`香菇`,amount:`5朵`},{name:`青菜`,amount:`3棵`},{name:`生姜`,amount:`5片`},{name:`料酒`,amount:`2勺`},{name:`盐`,amount:`适量`}],steps:[{order:1,text:`鸡斩块，排骨斩段，分别冷水下锅焯水去血沫，温水洗净。蛋饺提前做好（鸡蛋皮包肉馅煎熟）。`,image:e},{order:2,text:`取大砂锅，底层铺姜片和排骨，中层放鸡块和香菇，上层摆上蛋饺。`,image:e},{order:3,text:`加入料酒和足量清水（没过食材），大火烧开。`,image:e},{order:4,text:`转最小火，盖上锅盖慢炖40分钟至鸡和排骨酥烂、汤汁浓郁。`,image:e},{order:5,text:`最后放入青菜烫煮1分钟，加盐调味，连砂锅一起端上桌即可。`,image:e}],tips:`一品锅讲究"层层叠"——不同食材分层码放，各自保持本味又汤汁交融；蛋饺可以提前做好冷冻备用。`,coverImage:e},{id:`rec-101`,name:`刀板香`,difficulty:`easy`,duration:`20分钟`,cuisine:`徽菜`,ingredients:[{name:`猪肉`,amount:`200g`},{name:`生姜`,amount:`3片`},{name:`大葱`,amount:`1根`},{name:`大蒜`,amount:`2瓣`},{name:`料酒`,amount:`1勺`}],steps:[{order:1,text:`咸肉用温水刷洗干净，放入清水中浸泡30分钟去除部分咸味。`,image:e},{order:2,text:`咸肉切成0.5cm厚的薄片，均匀码放在蒸盘中。`,image:e},{order:3,text:`在肉片上铺姜片、葱段、蒜瓣，淋上料酒。`,image:e},{order:4,text:`蒸锅水开后放入，大火蒸15分钟至咸肉透明出油、香气四溢。`,image:e},{order:5,text:`取出后去掉姜葱蒜，将蒸出的汤汁淋在肉上，趁热食用。`,image:e}],tips:`咸肉一定要泡水去咸，否则会太咸；蒸的时间不宜过长，肉片变透明即可，蒸太久会老。`,coverImage:e},{id:`rec-102`,name:`徽州毛豆腐烧肉`,difficulty:`medium`,duration:`25分钟`,cuisine:`徽菜`,ingredients:[{name:`豆腐`,amount:`3块`},{name:`猪肉`,amount:`200g`},{name:`生姜`,amount:`3片`},{name:`大蒜`,amount:`3瓣`},{name:`生抽`,amount:`1勺`},{name:`老抽`,amount:`半勺`},{name:`料酒`,amount:`1勺`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`毛豆腐轻轻冲洗沥干切块，五花肉切薄片，姜蒜切片。`,image:e},{order:2,text:`锅中倒油，放入五花肉煸炒出油，炒至肉片卷曲微焦。`,image:e},{order:3,text:`加入姜蒜片爆香，倒入料酒、生抽和老抽翻炒上色。`,image:e},{order:4,text:`放入毛豆腐块，加半碗清水，轻轻推匀，盖上锅盖小火焖8分钟让豆腐吸足肉汁。`,image:e},{order:5,text:`开盖大火收汁至汤汁浓稠，轻轻翻动让豆腐裹满汤汁即可出锅。`,image:e}],tips:`毛豆腐比较嫩，焖煮时轻轻推动不要用力翻炒；五花肉的油脂会让毛豆腐更加香滑。`,coverImage:e},{id:`rec-103`,name:`徽式炒鳝糊`,difficulty:`medium`,duration:`20分钟`,cuisine:`徽菜`,ingredients:[{name:`黄鳝`,amount:`300g`},{name:`大蒜`,amount:`5瓣`},{name:`生姜`,amount:`3片`},{name:`酱油`,amount:`1勺`},{name:`醋`,amount:`半勺`},{name:`料酒`,amount:`1勺`},{name:`淀粉`,amount:`1勺`},{name:`胡椒粉`,amount:`少许`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`黄鳝宰杀洗净切丝，用料酒和少许盐抓匀去腥。蒜切末（用量要多），姜切丝。`,image:e},{order:2,text:`调碗汁：碗中混合酱油、醋、淀粉和2勺水搅匀。`,image:e},{order:3,text:`锅中倒油大火烧热，放入姜丝和一半蒜末爆香。`,image:e},{order:4,text:`倒入鳝丝大火快速翻炒至变色卷曲（约1分钟），淋入碗汁继续翻炒至芡汁浓稠。`,image:e},{order:5,text:`出锅装盘，撒上白胡椒粉和剩余的生蒜末，利用菜的余热激发出蒜香和白胡椒的辛香。`,image:e}],tips:`鳝丝炒得要快，保持嫩滑；出锅后撒生蒜末和白胡椒粉是徽式炒鳝糊的标志性做法，蒜香和胡椒香交织。`,coverImage:e},{id:`rec-104`,name:`新安江鱼头煲`,difficulty:`medium`,duration:`30分钟`,cuisine:`徽菜`,ingredients:[{name:`鱼头`,amount:`1个（约700g）`},{name:`豆腐`,amount:`1块`},{name:`香菇`,amount:`4朵`},{name:`生姜`,amount:`5片`},{name:`大蒜`,amount:`4瓣`},{name:`料酒`,amount:`2勺`},{name:`盐`,amount:`适量`},{name:`大葱`,amount:`2根`},{name:`食用油`,amount:`2勺`}],steps:[{order:1,text:`鱼头去鳃洗净，从中间劈开展平，用盐和料酒腌制10分钟后擦干水分。豆腐切厚片，香菇泡发。`,image:e},{order:2,text:`锅中倒油烧至七成热，放入鱼头，鱼皮面朝下中火煎至金黄（约3分钟），翻面再煎1分钟。`,image:e},{order:3,text:`砂锅中铺入姜片、蒜瓣和香菇，将煎好的鱼头放在上面。`,image:e},{order:4,text:`加入足量开水（没过鱼头），倒入料酒，大火烧开转小火焖煮15分钟至鱼汤变白。`,image:e},{order:5,text:`放入豆腐片，继续煮5分钟至豆腐入味，加盐调味，撒上葱段即可上桌。`,image:e}],tips:`鱼头先煎后炖，汤才会变白且不腥；加水时一定要加开水，冷水会让蛋白质凝固、汤不清白。`,coverImage:e},{id:`rec-105`,name:`葛粉圆子`,difficulty:`easy`,duration:`20分钟`,cuisine:`徽菜`,ingredients:[{name:`葛粉`,amount:`200g`},{name:`猪肉`,amount:`100g`},{name:`香菇`,amount:`3朵`},{name:`大葱`,amount:`1根`},{name:`生姜`,amount:`2片`},{name:`生抽`,amount:`1勺`},{name:`盐`,amount:`适量`},{name:`食用油`,amount:`1勺`}],steps:[{order:1,text:`香菇泡发切小丁，葱姜切末。猪肉末加香菇丁、葱姜末、生抽和盐调匀成馅料。`,image:e},{order:2,text:`葛粉放入碗中，用刚烧开的沸水慢慢冲入，边冲边用筷子搅拌至粉糊透明成团。`,image:e},{order:3,text:`手上沾少许油防粘，取一团葛粉团搓圆压扁，包入肉馅，收口搓成圆子。`,image:e},{order:4,text:`蒸笼刷油防粘，将包好的葛粉圆子放入，蒸锅水开后大火蒸10分钟至圆子透明晶莹即可。`,image:e}],tips:`葛粉一定要用刚烧开的沸水冲，水温不够粉不会糊化；手上抹油防止面团粘手。`,coverImage:e}],n={easy:`简单`,medium:`中等`,hard:`困难`},r=[`川菜`,`粤菜`,`鲁菜`,`苏菜`,`闽菜`,`浙菜`,`湘菜`,`徽菜`,`家常`];export{n,t as r,r as t};